INSERT INTO busi_question_categories (id, name, description, is_deleted, created_by_id, created_at, updated_at) VALUES
(1, '资产', '资产类业务知识考核，涵盖固定资产、流动资产、无形资产等', 0, 2, NOW(), NOW()),
(2, '负债', '负债类业务知识考核，涵盖流动负债、长期负债、或有负债等', 0, 2, NOW(), NOW()),
(3, '制度', '银行制度规范考核，涵盖风控制度、合规制度、操作流程等', 0, 2, NOW(), NOW());
INSERT INTO busi_questions (question_type, content, options, correct_answer, analysis, category_id, difficulty, default_score, org_id, org_nm, is_deleted, created_by_id, created_at, updated_at) VALUES
('single_choice', '固定资产的确认条件中，以下哪项不是必须满足的？', JSON_ARRAY('A. 与该资产相关的经济利益很可能流入企业', 'B. 该资产的成本能够可靠计量', 'C. 该资产必须是有形资产', 'D. 企业拥有该资产的所有权或控制权'), 'C', '固定资产可以是有形或无形的，关键是要满足经济利益流入和成本可靠计量两个条件。', 1, 'easy', 2.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('single_choice', '以下哪种折旧方法不属于加速折旧法？', JSON_ARRAY('A. 双倍余额递减法', 'B. 年数总和法', 'C. 年限平均法', 'D. 递减折旧法'), 'C', '年限平均法是直线折旧法，每年折旧额相等。双倍余额递减法和年数总和法属于加速折旧法。', 1, 'easy', 2.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('single_choice', '银行持有至到期投资的后续计量采用什么方法？', JSON_ARRAY('A. 公允价值计量', 'B. 摊余成本计量', 'C. 成本与市价孰低', 'D. 可变现净值'), 'B', '持有至到期投资按摊余成本进行后续计量，反映实际利率法下的利息收入。', 1, 'medium', 2.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('single_choice', '贷款损失准备的计提方法是？', JSON_ARRAY('A. 直接转销法', 'B. 备抵法', 'C. 余额百分比法', 'D. 账龄分析法'), 'B', '根据《企业会计准则》，贷款损失准备应采用备抵法核算，不得采用直接转销法。', 1, 'medium', 2.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('single_choice', '无形资产摊销年限不应超过多少年？', JSON_ARRAY('A. 5年', 'B. 10年', 'C. 20年', 'D. 按合同或法律规定'), 'D', '无形资产的摊销年限应按合同性权利或法定权利的期限确定，无明确期限的不摊销但需减值测试。', 1, 'medium', 2.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('single_choice', '可供出售金融资产的公允价值变动计入哪个科目？', JSON_ARRAY('A. 投资收益', 'B. 公允价值变动损益', 'C. 其他综合收益', 'D. 资本公积'), 'C', '可供出售金融资产的公允价值变动计入其他综合收益，处置时转入投资收益。', 1, 'hard', 3.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('single_choice', '以下哪项不属于流动资产？', JSON_ARRAY('A. 应收账款', 'B. 交易性金融资产', 'C. 固定资产', 'D. 存货'), 'C', '固定资产属于非流动资产，使用年限超过一个会计年度。应收账款、存货、交易性金融资产都属于流动资产。', 1, 'easy', 2.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('single_choice', '资产减值测试的频率是？', JSON_ARRAY('A. 每月一次', 'B. 每季度一次', 'C. 每年至少一次', 'D. 只在有减值迹象时'), 'C', '企业应当在资产负债表日判断资产是否存在可能发生减值的迹象，至少每年进行一次减值测试。', 1, 'medium', 2.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('single_choice', '银行最重要的盈利资产是？', JSON_ARRAY('A. 固定资产', 'B. 现金及存放央行款项', 'C. 贷款及垫款', 'D. 无形资产'), 'C', '贷款及垫款是商业银行最重要的盈利性资产，其利息收入占银行总收入的绝大部分。', 1, 'easy', 2.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('single_choice', '长期股权投资采用权益法核算时，被投资单位实现净利润，投资方应？', JSON_ARRAY('A. 不作处理', 'B. 确认投资收益', 'C. 冲减投资成本', 'D. 确认资本公积'), 'B', '权益法下，投资方应按持股比例确认应享有的被投资单位净利润份额，计入投资收益。', 1, 'medium', 2.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('single_choice', '固定资产的入账价值不包括？', JSON_ARRAY('A. 购买价款', 'B. 运输费', 'C. 安装费', 'D. 日常维修费'), 'D', '固定资产的入账价值包括达到预定可使用状态前的一切合理必要支出。日常维修费作为当期费用处理。', 1, 'easy', 2.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('single_choice', '交易性金融资产初始确认时，交易费用如何处理？', JSON_ARRAY('A. 计入资产成本', 'B. 计入当期损益', 'C. 计入资本公积', 'D. 递延处理'), 'B', '交易性金融资产的交易费用直接计入当期损益（投资收益），不计入资产成本。', 1, 'medium', 2.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('single_choice', '以下哪项不计入存货成本？', JSON_ARRAY('A. 采购价格', 'B. 运输费用', 'C. 仓储保管费', 'D. 可抵扣增值税'), 'D', '可抵扣的增值税进项税额不计入存货成本，而计入应交税费。运输费、仓储费属于使存货达到可销售状态的必要支出。', 1, 'medium', 2.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('single_choice', '银行抵债资产的入账价值应按什么确定？', JSON_ARRAY('A. 账面价值', 'B. 公允价值', 'C. 评估价值', 'D. 协商价格'), 'B', '抵债资产应按公允价值进行初始计量，公允价值与债权账面价值的差额计入当期损益。', 1, 'hard', 3.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('single_choice', '商誉的减值测试应当？', JSON_ARRAY('A. 单独测试', 'B. 结合资产组测试', 'C. 不需要测试', 'D. 按年限摊销'), 'B', '商誉应当结合相关的资产组或资产组组合进行减值测试，且每年至少一次。商誉不计提摊销。', 1, 'hard', 3.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('single_choice', '应收款项坏账准备的计提体现什么会计原则？', JSON_ARRAY('A. 权责发生制', 'B. 谨慎性原则', 'C. 重要性原则', 'D. 实质重于形式'), 'B', '计提坏账准备体现了谨慎性原则，不高估资产和收益，不低估负债和费用。', 1, 'easy', 2.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('single_choice', '银行间同业拆借属于哪种资产？', JSON_ARRAY('A. 固定资产', 'B. 长期资产', 'C. 流动资产', 'D. 递延资产'), 'C', '同业拆借通常期限较短（1天到1年），属于流动资产中的拆出资金科目。', 1, 'easy', 2.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('single_choice', '公允价值计量的输入值分为几个层级？', JSON_ARRAY('A. 2个', 'B. 3个', 'C. 4个', 'D. 5个'), 'B', '公允价值分为三个层级：第一层级（活跃市场报价）、第二层级（可观察输入值）、第三层级（不可观察输入值）。', 1, 'medium', 2.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('single_choice', '资产证券化中，基础资产应当满足什么条件？', JSON_ARRAY('A. 必须是有形资产', 'B. 能产生可预测的现金流', 'C. 必须是固定资产', 'D. 必须是无风险资产'), 'B', '资产证券化的基础资产必须能够在未来产生可预测的、稳定的现金流。', 1, 'hard', 3.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('single_choice', '对于使用寿命不确定的无形资产，应如何处理？', JSON_ARRAY('A. 按10年摊销', 'B. 不摊销但每年减值测试', 'C. 按20年摊销', 'D. 一次性计入费用'), 'B', '使用寿命不确定的无形资产不应摊销，但应当在每个会计期间进行减值测试。', 1, 'medium', 2.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW());
INSERT INTO busi_questions (question_type, content, options, correct_answer, analysis, category_id, difficulty, default_score, org_id, org_nm, is_deleted, created_by_id, created_at, updated_at) VALUES
('multiple_choice', '以下哪些属于银行资产？', JSON_ARRAY('A. 客户存款', 'B. 贷款及垫款', 'C. 存放央行款项', 'D. 固定资产'), JSON_ARRAY('B', 'C', 'D'), '贷款、存放央行款项、固定资产都属于银行资产。客户存款属于银行的负债。', 1, 'easy', 3.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('multiple_choice', '固定资产的特征包括？', JSON_ARRAY('A. 为生产商品、提供劳务而持有', 'B. 使用寿命超过一个会计年度', 'C. 必须是有形资产', 'D. 价值较高'), JSON_ARRAY('A', 'B'), '固定资产的两个核心特征：持有目的和使用寿命。有形/无形不是必要条件，价值高低也不是会计准则规定的必要条件。', 1, 'easy', 3.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('multiple_choice', '以下哪些属于金融资产？', JSON_ARRAY('A. 库存现金', 'B. 应收账款', 'C. 持有至到期投资', 'D. 长期股权投资'), JSON_ARRAY('A', 'B', 'C', 'D'), '上述四项都属于金融资产。金融资产包括现金、权益工具投资、从其他方收取现金的合同权利等。', 1, 'easy', 3.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('multiple_choice', '固定资产折旧方法包括？', JSON_ARRAY('A. 年限平均法', 'B. 工作量法', 'C. 双倍余额递减法', 'D. 年数总和法'), JSON_ARRAY('A', 'B', 'C', 'D'), '四种都是《企业会计准则》允许的固定资产折旧方法，企业应选用能反映资产经济利益的消耗方式的折旧方法。', 1, 'medium', 3.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('multiple_choice', '应收账款坏账准备的计提方法有？', JSON_ARRAY('A. 余额百分比法', 'B. 账龄分析法', 'C. 个别认定法', 'D. 直接转销法'), JSON_ARRAY('A', 'B', 'C'), '余额百分比法、账龄分析法、个别认定法都是计提坏账准备的方法。直接转销法已被会计准则禁止。', 1, 'medium', 3.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('multiple_choice', '以下哪些属于无形资产？', JSON_ARRAY('A. 专利权', 'B. 商标权', 'C. 土地使用权', 'D. 商誉'), JSON_ARRAY('A', 'B', 'C'), '专利权、商标权、土地使用权都是无形资产。商誉在会计上单独列示，虽在广义上可视为无形资产，但会计准则将其与企业合并产生的商誉单列处理。', 1, 'medium', 3.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('multiple_choice', '资产减值迹象包括？', JSON_ARRAY('A. 市价大幅下跌', 'B. 企业经营环境发生重大不利变化', 'C. 资产陈旧过时', 'D. 资产闲置'), JSON_ARRAY('A', 'B', 'C', 'D'), '以上均为常见的资产减值迹象，企业需要据此进行减值测试。', 1, 'easy', 3.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('multiple_choice', '以公允价值计量的金融资产包括？', JSON_ARRAY('A. 交易性金融资产', 'B. 可供出售金融资产', 'C. 持有至到期投资', 'D. 贷款及应收款项'), JSON_ARRAY('A', 'B'), '交易性金融资产和可供出售金融资产都按公允价值计量。持有至到期投资和贷款按摊余成本计量。', 1, 'medium', 3.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('multiple_choice', '长期股权投资的核算方法有？', JSON_ARRAY('A. 成本法', 'B. 权益法', 'C. 市价法', 'D. 重置成本法'), JSON_ARRAY('A', 'B'), '长期股权投资采用成本法（控制）或权益法（重大影响/共同控制）核算。市价法和重置成本法不是长期股权投资的标准核算方法。', 1, 'medium', 3.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('multiple_choice', '存货的发出计价方法包括？', JSON_ARRAY('A. 先进先出法', 'B. 加权平均法', 'C. 个别计价法', 'D. 后进先出法'), JSON_ARRAY('A', 'B', 'C'), '先进先出、加权平均和个别计价法都允许。后进先出法(LIFO)已被我国会计准则取消。', 1, 'medium', 3.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('multiple_choice', '以下哪些属于银行表内资产？', JSON_ARRAY('A. 各项贷款', 'B. 债券投资', 'C. 银行承兑汇票', 'D. 存放同业款项'), JSON_ARRAY('A', 'B', 'D'), '各项贷款、债券投资、存放同业款项都属于表内资产。银行承兑汇票属于表外业务/或有事项。', 1, 'hard', 3.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('multiple_choice', '资产组认定时需要考虑的因素有？', JSON_ARRAY('A. 生产经营活动的方式', 'B. 管理层的决策方式', 'C. 资产的物理位置', 'D. 资产的购入价格'), JSON_ARRAY('A', 'B'), '资产组的认定应当以资产组产生的主要现金流入是否独立于其他资产或资产组为依据，同时考虑管理层管理生产经营活动的方式。', 1, 'hard', 3.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('multiple_choice', '商业银行流动性资产包括？', JSON_ARRAY('A. 库存现金', 'B. 超额存款准备金', 'C. 一个月内到期的债券', 'D. 长期股权投资'), JSON_ARRAY('A', 'B', 'C'), '库存现金、超额存款准备金、短期内到期的债券都是流动性资产。长期股权投资不具备即时变现能力。', 1, 'easy', 3.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('multiple_choice', '影响固定资产折旧的因素有？', JSON_ARRAY('A. 固定资产原值', 'B. 预计净残值', 'C. 预计使用寿命', 'D. 市场利率'), JSON_ARRAY('A', 'B', 'C'), '固定资产折旧的三要素：原值、净残值、使用寿命。市场利率不直接影响折旧计算。', 1, 'easy', 3.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('multiple_choice', '以下哪些情况需要对资产进行减值测试？', JSON_ARRAY('A. 资产市价大幅下跌', 'B. 资产已经陈旧过时', 'C. 企业经营环境发生重大不利变化', 'D. 资产使用方式发生重大变化'), JSON_ARRAY('A', 'B', 'C', 'D'), '以上情况都可能表明资产发生了减值，需要进行减值测试。', 1, 'medium', 3.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('multiple_choice', '银行信贷资产包括？', JSON_ARRAY('A. 流动资金贷款', 'B. 固定资产贷款', 'C. 个人住房贷款', 'D. 贴现'), JSON_ARRAY('A', 'B', 'C', 'D'), '以上四项都是银行信贷资产的组成部分，涵盖对公贷款、个人贷款和票据融资。', 1, 'easy', 3.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('multiple_choice', '投资性房地产的计量模式有？', JSON_ARRAY('A. 成本模式', 'B. 公允价值模式', 'C. 重置成本模式', 'D. 可变现净值模式'), JSON_ARRAY('A', 'B'), '投资性房地产可以采用成本模式或公允价值模式进行后续计量，但同一企业只能采用一种模式。', 1, 'medium', 3.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('multiple_choice', '应收款项包括？', JSON_ARRAY('A. 应收账款', 'B. 应收票据', 'C. 其他应收款', 'D. 预收账款'), JSON_ARRAY('A', 'B', 'C'), '应收账款、应收票据、其他应收款都属于应收款项。预收账款是负债类科目。', 1, 'easy', 3.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('multiple_choice', '关于资产减值，以下说法正确的有？', JSON_ARRAY('A. 固定资产减值损失一经确认不得转回', 'B. 存货跌价准备可以转回', 'C. 商誉减值损失不得转回', 'D. 所有资产减值都不得转回'), JSON_ARRAY('A', 'B', 'C'), '固定资产、无形资产、商誉等长期资产的减值不得转回；但存货、应收账款等流动资产的减值在减值因素消失后可以转回。', 1, 'hard', 3.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('multiple_choice', '生物资产分为哪几类？', JSON_ARRAY('A. 消耗性生物资产', 'B. 生产性生物资产', 'C. 公益性生物资产', 'D. 交易性生物资产'), JSON_ARRAY('A', 'B', 'C'), '根据《企业会计准则第5号》，生物资产分为消耗性、生产性和公益性三类。没有交易性生物资产这一分类。', 1, 'medium', 3.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW());
INSERT INTO busi_questions (question_type, content, options, correct_answer, analysis, category_id, difficulty, default_score, org_id, org_nm, is_deleted, created_by_id, created_at, updated_at) VALUES
('true_false', '固定资产必须是有形资产。', JSON_ARRAY(), '错', '虽然大多数固定资产是有形的，但会计准则并未严格限定固定资产必须是有形资产，核心是满足持有目的和使用寿命条件。', 1, 'easy', 2.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('true_false', '存货跌价准备在减值因素消失后可以转回。', JSON_ARRAY(), '对', '存货跌价准备属于流动资产减值准备，在导致减值的因素消失后，可以以原已计提的金额为限予以转回。', 1, 'easy', 2.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('true_false', '固定资产减值损失确认后可以转回。', JSON_ARRAY(), '错', '根据会计准则，固定资产、无形资产、商誉等长期资产的减值损失一经确认，在以后会计期间不得转回。', 1, 'medium', 2.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('true_false', '交易性金融资产按公允价值进行后续计量。', JSON_ARRAY(), '对', '交易性金融资产属于以公允价值计量且其变动计入当期损益的金融资产，期末按公允价值计量。', 1, 'easy', 2.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('true_false', '企业至少应在每年年末对所有资产进行一次全面减值测试。', JSON_ARRAY(), '错', '企业需要每年测试的是存在减值迹象的资产以及商誉和使用寿命不确定的无形资产，并非所有资产都需要每年减值测试。', 1, 'medium', 2.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('true_false', '长期股权投资采用成本法核算时，被投资单位宣告分派现金股利，投资方应确认投资收益。', JSON_ARRAY(), '对', '成本法下，投资方在被投资单位宣告分派现金股利或利润时，确认为当期投资收益。', 1, 'medium', 2.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('true_false', '银行的不良贷款属于银行资产的减少。', JSON_ARRAY(), '错', '不良贷款仍是银行的资产，只是计提了相应的贷款损失准备，表现为资产价值的减损，而非资产的直接减少。', 1, 'easy', 2.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('true_false', '商誉可以单独进行减值测试。', JSON_ARRAY(), '错', '商誉不能单独进行减值测试，必须结合相关的资产组或资产组组合进行。这是商誉的独特性质决定的。', 1, 'medium', 2.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('true_false', '资产的账面价值等于其初始入账价值。', JSON_ARRAY(), '错', '账面价值=初始入账价值-累计折旧/摊销-减值准备。后续计量中折旧、摊销和减值都会影响账面价值。', 1, 'easy', 2.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('true_false', '贷款按五级分类中，次级类贷款属于不良贷款。', JSON_ARRAY(), '对', '五级分类中，次级、可疑、损失三类统称为不良贷款。正常和关注类属于正常贷款。', 1, 'easy', 2.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('true_false', '所有无形资产都需要进行摊销。', JSON_ARRAY(), '错', '使用寿命不确定的无形资产（如某些商标权）不需要摊销，但需要每年进行减值测试。', 1, 'medium', 2.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('true_false', '银行存放央行的法定存款准备金属于银行的可用资金。', JSON_ARRAY(), '错', '法定存款准备金是银行按存款比例缴存央行的强制性准备金，不能随意动用。超额存款准备金才是银行可自由支配的资金。', 1, 'medium', 2.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('true_false', '资产组产生的现金流入应当基本上独立于其他资产或资产组。', JSON_ARRAY(), '对', '这是会计准则对资产组认定的基本要求，独立产生现金流是资产组的最核心特征。', 1, 'medium', 2.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('true_false', '投资性房地产只能采用成本模式进行后续计量。', JSON_ARRAY(), '错', '投资性房地产可以采用成本模式或公允价值模式，但同一企业只能选择一种模式且不能随意变更。', 1, 'easy', 2.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('true_false', '可供出售金融资产减值损失可以通过损益转回。', JSON_ARRAY(), '错', '可供出售权益工具的减值损失不得通过损益转回，应通过其他综合收益转回。债务工具可通过损益转回。', 1, 'hard', 3.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('true_false', '持有至到期投资可以重分类为可供出售金融资产。', JSON_ARRAY(), '对', '在满足一定条件下（如出售比例超过规定限额），持有至到期投资可以重分类为可供出售金融资产。', 1, 'medium', 2.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('true_false', '银行买入返售金融资产属于信用资产。', JSON_ARRAY(), '对', '买入返售金融资产是银行按协议约定先买入再按固定价格返售的金融资产，本质上是以证券为质押的短期融资，属于信用资产。', 1, 'hard', 3.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('true_false', '以公允价值计量的资产不需要计提折旧或摊销。', JSON_ARRAY(), '错', '并非所有以公允价值计量的资产都不提折旧。投资性房地产以公允价值模式计量时不提折旧，但固定资产即使以公允价值计量（如重估模式）仍需提折旧。', 1, 'hard', 3.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('true_false', '银行贷款五级分类中，关注类贷款不需要计提专项准备。', JSON_ARRAY(), '错', '关注类贷款虽然不属于不良贷款，但存在一些可能影响偿还的不利因素，按规定应计提2%的专项准备金。', 1, 'medium', 2.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('true_false', '无形资产研究与开发阶段的支出都应资本化。', JSON_ARRAY(), '错', '研究阶段的支出应全部费用化计入当期损益，只有开发阶段且满足资本化条件的支出才能确认为无形资产。', 1, 'easy', 2.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW());
INSERT INTO busi_questions (question_type, content, options, correct_answer, analysis, category_id, difficulty, default_score, org_id, org_nm, is_deleted, created_by_id, created_at, updated_at) VALUES
('fill_blank', '固定资产账面价值等于原值减去累计折旧和______。', JSON_ARRAY(), '减值准备', '账面价值=原值-累计折旧-减值准备，三者综合反映固定资产的实际价值。', 1, 'easy', 3.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('fill_blank', '银行贷款五级分类中，正常、关注、______、可疑、损失。', JSON_ARRAY(), '次级', '五级分类依次为：正常→关注→次级→可疑→损失，后三级统称为不良贷款。', 1, 'easy', 3.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('fill_blank', '持有至到期投资按______进行后续计量。', JSON_ARRAY(), '摊余成本', '持有至到期投资采用实际利率法，按摊余成本计量，各期确认利息收入。', 1, 'medium', 3.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('fill_blank', '交易性金融资产的交易费用计入______科目。', JSON_ARRAY(), '投资收益', '交易性金融资产的相关交易费用直接计入当期损益（投资收益），这是与其他金融资产的重要区别。', 1, 'medium', 3.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('fill_blank', '企业合并形成的商誉，至少应当在每年______进行减值测试。', JSON_ARRAY(), '年末', '无论是否有减值迹象，商誉都应在每年年度终了进行减值测试，这是商誉的特殊规定。', 1, 'easy', 3.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('fill_blank', '存货期末计量采用成本与______孰低法。', JSON_ARRAY(), '可变现净值', '存货应按成本与可变现净值孰低计量，当可变现净值低于成本时计提存货跌价准备。', 1, 'easy', 3.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('fill_blank', '银行法定存款准备金由______统一规定缴存比例。', JSON_ARRAY(), '中国人民银行', '法定存款准备金率由中国人民银行根据宏观调控需要制定和调整。', 1, 'easy', 3.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('fill_blank', '无形资产摊销方法应当反映与该资产有关的______的预期消耗方式。', JSON_ARRAY(), '经济利益', '无形资产的摊销方法应反映其经济利益的预期实现方式，无法可靠确定时采用直线法。', 1, 'medium', 3.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('fill_blank', '贷款损失准备的计提采用______法。', JSON_ARRAY(), '备抵', '我国会计准则和国际准则都要求使用备抵法确认贷款损失，不得采用直接转销法。', 1, 'easy', 3.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('fill_blank', '长期股权投资达到控制时采用______法核算。', JSON_ARRAY(), '成本', '当投资方对被投资单位具有控制（通常持股>50%）时，长期股权投资采用成本法核算。', 1, 'medium', 3.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('fill_blank', '可供出售金融资产公允价值变动计入______。', JSON_ARRAY(), '其他综合收益', '可供出售金融资产的公允价值变动计入其他综合收益，不影响当期利润，处置时才转入投资收益。', 1, 'medium', 3.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('fill_blank', '资产预计可收回金额为公允价值减去处置费用后的净额与______两者中较高者。', JSON_ARRAY(), '预计未来现金流量的现值', '可收回金额取两者的较高值，这体现了资产减值的谨慎性评估。', 1, 'hard', 4.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('fill_blank', '银行现金资产包括库存现金、存放央行款项和______。', JSON_ARRAY(), '存放同业款项', '商业银行的一级储备主要包括库存现金、存放央行超额准备金以及存放同业款项。', 1, 'medium', 3.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('fill_blank', '固定资产双倍余额递减法的折旧率是直线法折旧率的______倍。', JSON_ARRAY(), '2', '双倍余额递减法就是在不考虑残值的情况下，用直线法折旧率的两倍作为折旧率。最后两年改为直线法。', 1, 'easy', 3.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('fill_blank', '投资性房地产采用公允价值模式计量的，不计提______。', JSON_ARRAY(), '折旧或摊销', '公允价值模式下的投资性房地产不计提折旧或摊销，以期末公允价值调整账面价值。', 1, 'medium', 3.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('fill_blank', '银行抵债资产应当在取得后______内予以处置。', JSON_ARRAY(), '2年', '根据相关规定，银行取得的抵债资产原则上应当在取得后2年内予以处置变现。', 1, 'hard', 4.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('fill_blank', '固定资产的折旧方法一经确定，不得______。', JSON_ARRAY(), '随意变更', '折旧方法作为会计估计，虽然可以变更，但不得随意变更，变更时需作为会计估计变更处理并披露。', 1, 'easy', 3.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('fill_blank', '应收账款坏账准备的计提体现了______原则。', JSON_ARRAY(), '谨慎性', '不高估资产和收益、不低估负债和费用，这体现了会计核算的谨慎性原则。', 1, 'easy', 3.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('fill_blank', '公允价值计量分为______个层级。', JSON_ARRAY(), '三', '三个层级：第一层级是活跃市场未经调整的报价，第二层级是可观察输入值，第三层级是不可观察输入值。', 1, 'easy', 3.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('fill_blank', '资产组的认定应当以资产组能否______产生现金流入为依据。', JSON_ARRAY(), '独立', '资产组的核心特征是能够独立于其他资产或资产组产生现金流入。', 1, 'medium', 3.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW());
INSERT INTO busi_questions (question_type, content, options, correct_answer, analysis, category_id, difficulty, default_score, org_id, org_nm, is_deleted, created_by_id, created_at, updated_at) VALUES
('short_answer', '请简述固定资产的定义和确认条件。', JSON_ARRAY(), '固定资产是指为生产商品、提供劳务、出租或经营管理而持有的，使用寿命超过一个会计年度的有形资产。确认条件：(1)与该资产相关的经济利益很可能流入企业；(2)该资产的成本能够可靠计量。', '掌握固定资产基本概念。', 1, 'easy', 5.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('short_answer', '请分析银行贷款五级分类的内容和拨备要求。', JSON_ARRAY(), '五级分类：正常类(1%拨备)、关注类(2%拨备)、次级类(25%拨备)、可疑类(50%拨备)、损失类(100%拨备)。后三类统称为不良贷款。分类依据包括借款人的还款能力、还款意愿、担保情况等。', '五级分类是银行信用风险管理的核心。', 1, 'medium', 5.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('short_answer', '请解释资产减值测试中可收回金额的确定方法。', JSON_ARRAY(), '可收回金额为以下两者中较高者：(1)公允价值减去处置费用的净额；(2)资产预计未来现金流量的现值。当可收回金额低于账面价值时，差额计提减值准备。', '可收回金额的确定是减值测试的核心步骤。', 1, 'medium', 5.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('short_answer', '请说明交易性金融资产与可供出售金融资产在会计处理上的主要区别。', JSON_ARRAY(), '1.初始计量：交易费用处理不同，前者费用化(计入投资收益)，后者资本化(计入资产成本)；2.后续计量：都按公允价值，但变动前者计入公允价值变动损益，后者计入其他综合收益；3.减值：前者不考虑减值，后者需要测试减值。', '两者虽都按公允价值计量但损益归属不同。', 1, 'medium', 5.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('short_answer', '请简述长期股权投资成本法和权益法的适用条件。', JSON_ARRAY(), '成本法适用条件：投资方对被投资单位具有控制(通常持股>50%)。权益法适用条件：投资方对被投资单位具有共同控制或重大影响(通常持股20%-50%)。成本法下仅在被投资方宣告分红时确认收益；权益法下按持股比例确认被投资方净利润份额。', '两种方法的选用取决于投资方对被投资方的影响程度。', 1, 'medium', 5.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('short_answer', '请说明银行资产中贷款损失准备的计提方法及其影响。', JSON_ARRAY(), '计提方法：(1)单项评估——对金额重大的贷款逐笔评估；(2)组合评估——对金额不重大的贷款按组合计提。影响：直接减少当期利润，但形成贷款损失准备(资产的备抵科目)，实际核销时才减少贷款账面金额。', '贷款损失准备是银行最重要的风险缓冲机制。', 1, 'hard', 6.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('short_answer', '请解释资产证券化的基本流程和会计处理要点。', JSON_ARRAY(), '基本流程：发起机构将基础资产转让给特殊目的载体(SPV)→SPV以资产池现金流为支持发行证券→投资者购买证券。会计要点：判断是否满足终止确认条件（风险报酬是否转移）是关键。满足条件则终止确认基础资产，否则作为担保融资处理。', '资产证券化的核心是风险报酬是否实质转移。', 1, 'hard', 6.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('short_answer', '请说明无形资产研究与开发阶段支出的不同会计处理。', JSON_ARRAY(), '研究阶段：支出全部费用化，计入当期管理费用。开发阶段：满足资本化条件的支出确认为无形资产，包括完成该无形资产技术上具有可行性、有使用或出售意图、能产生经济利益、有足够资源支持完成等五个条件。不符合条件的开发支出同样费用化。', '区分研究与开发阶段是无形资产会计的核心。', 1, 'easy', 5.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('short_answer', '请简述投资性房地产的定义及两种计量模式的区别。', JSON_ARRAY(), '投资性房地产是指为赚取租金或资本增值而持有的房地产。两种模式：(1)成本模式——按成本减累计折旧和减值计量，与固定资产一致；(2)公允价值模式——期末按公允价值调整账面价值，差额计入当期损益，不计提折旧。同一企业只能采用一种模式。', '公允价值模式提供更及时的资产价值信息。', 1, 'easy', 5.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('short_answer', '请简述公允价值计量的三个层级及各自特征。', JSON_ARRAY(), '第一层级：活跃市场中相同资产未经调整的报价，最优级输入值。第二层级：除第一层级外可直接或间接观察到的输入值，如同类资产活跃市场报价。第三层级：不可观察输入值，基于企业自身数据的估计。优先使用第一层级。', '三个层级体现了公允价值计量的可靠性递减。', 1, 'medium', 5.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('short_answer', '请说明银行存款准备金制度的内容和作用。', JSON_ARRAY(), '法定存款准备金：商业银行按存款余额的一定比例缴存央行，比例由央行制定，用于控制货币乘数和信贷规模。超额存款准备金：超出法定部分，银行可自由支配。作用：(1)货币政策工具——调整准备金率调节货币供应量；(2)流动性管理——保障银行的兑付能力。', '准备金制度是央行货币政策三大工具之一。', 1, 'easy', 5.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('short_answer', '请分析固定资产折旧方法的选用依据及变更处理。', JSON_ARRAY(), '选用依据：折旧方法应反映固定资产经济利益的预期消耗方式。常用的有年限平均法、工作量法、双倍余额递减法和年数总和法。变更处理：折旧方法作为会计估计，一经确定不得随意变更。如需变更，应作为会计估计变更处理，采用未来适用法，并披露变更原因和影响。', '折旧方法的选用影响各期费用和资产账面价值。', 1, 'medium', 5.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('short_answer', '请解释商誉的本质及其减值测试要求。', JSON_ARRAY(), '商誉本质：企业合并成本超过取得的被购买方可辨认净资产公允价值份额的差额，代表并购方预期被购买方未来超额收益能力。测试要求：(1)至少每年年度终了进行减值测试；(2)必须结合相关资产组进行，不能单独测试；(3)减值损失一经确认不得转回。', '商誉的"不可辨认性"决定了其独特的会计处理方式。', 1, 'hard', 6.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('short_answer', '请说明存货期末计量的成本与可变现净值孰低法。', JSON_ARRAY(), '期末按成本与可变现净值孰低计量：可变现净值=估计售价-至完工估计成本-估计销售费用。当可变现净值低于成本时，按差额计提存货跌价准备。后续若减值因素消失，可在原已计提的金额内转回。体现了谨慎性原则。', '存货减值可以转回，这是与长期资产减值的重要区别。', 1, 'easy', 5.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('short_answer', '请简述银行抵债资产的会计处理要点。', JSON_ARRAY(), '初始确认：按公允价值入账，公允价值与债权账面价值的差额计入当期损益。后续处理：(1)持有期间不计提折旧摊销，但需定期评估可收回金额；(2)原则上应在2年内处置；(3)处置时差额计入当期损益；(4)期末测试减值，减值损失计入损益。', '抵债资产的及时处置是监管关注重点。', 1, 'medium', 5.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('short_answer', '请分析资产组与总部分摊的会计处理。', JSON_ARRAY(), '资产组的认定：能够独立产生现金流的最小资产组合。相关总部资产：先分摊至各资产组，再对各资产组测试减值。无法分摊的总部资产：先将除该项总部资产外的其他资产组合并测试，然后将测试结果与包含该项总部资产的更大资产组合并测试。', '总部资产无法单独测试减值，需合理分摊。', 1, 'hard', 6.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('short_answer', '请说明银行信贷资产的主要风险分类和管理措施。', JSON_ARRAY(), '分类：正常、关注、次级、可疑、损失五类。管理措施：(1)贷前调查——严格审查借款人资质和还款能力；(2)贷中审查——独立审批、审贷分离；(3)贷后检查——定期跟踪贷款使用和借款人状况；(4)风险缓释——要求担保、抵押等；(5)拨备计提——按分类档次计提贷款损失准备。', '信贷资产是银行最主要的风险资产类别。', 1, 'easy', 5.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('short_answer', '请比较可供出售金融资产与持有至到期投资的异同。', JSON_ARRAY(), '相同点：初始确认时交易费用都计入资产成本。不同点：(1)计量属性——前者按公允价值，后者按摊余成本；(2)公允价值变动——前者计入其他综合收益，后者不反应；(3)减值——前者需要，后者不需要；(4)持有意图——前者为可供出售，后者为持有至到期。', '持有意图的不同决定了会计分类的不同。', 1, 'medium', 5.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('short_answer', '请解释金融资产重分类的条件和限制。', JSON_ARRAY(), '重分类条件：业务模式发生改变时。主要限制：(1)以公允价值计量且其变动计入当期损益的金融资产不能重分类；(2)持有至到期投资在出售超过一定比例后必须全部重分类为可供出售金融资产；(3)重分类日公允价值与账面价值的差额处理取决于重分类方向。', '重分类需有充分证据证明业务模式确实发生了改变。', 1, 'hard', 6.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('short_answer', '请简述银行表外资产的含义和风险特征。', JSON_ARRAY(), '表外资产：未在资产负债表中确认但可能形成银行未来资产或负债的项目。包括：(1)银行承兑汇票——承诺在未来支付；(2)信用证——为国际贸易提供担保；(3)贷款承诺——承诺在未来提供贷款；(4)衍生金融工具。风险：或有性——可能转化为表内资产；杠杆性——以较少的保证金撬动较大金额。', '表外资产虽不在表内，但风险不可忽视。', 1, 'easy', 5.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW());
INSERT INTO busi_questions (question_type, content, options, correct_answer, analysis, category_id, difficulty, default_score, org_id, org_nm, is_deleted, created_by_id, created_at, updated_at) VALUES
('single_choice', '以下哪项属于银行的负债？', JSON_ARRAY('A. 贷款', 'B. 客户存款', 'C. 固定资产', 'D. 存放央行款项'), 'B', '客户存款是银行最主要的资金来源，属于银行的负债。贷款、固定资产和存放央行款项都属于银行资产。', 2, 'easy', 2.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('single_choice', '以下哪种负债的偿还期限通常在一年以内？', JSON_ARRAY('A. 应付债券', 'B. 长期借款', 'C. 短期借款', 'D. 递延所得税负债'), 'C', '短期借款的偿还期限在一年以内（含一年），属于流动负债。应付债券和长期借款属于非流动负债。', 2, 'easy', 2.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('single_choice', '或有负债在什么情况下需要确认？', JSON_ARRAY('A. 任何时候都需要确认', 'B. 很可能导致经济利益流出且金额能可靠计量', 'C. 金额能够可靠计量即可', 'D. 只要存在潜在义务就确认'), 'B', '或有负债只有在同时满足"很可能"（>50%概率）导致经济利益流出和金额能可靠计量两个条件时才确认为预计负债。', 2, 'medium', 2.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('single_choice', '应付职工薪酬不包括以下哪项？', JSON_ARRAY('A. 工资', 'B. 社会保险费', 'C. 差旅费', 'D. 住房公积金'), 'C', '差旅费属于管理费用，不属于应付职工薪酬。应付职工薪酬包括工资、奖金、津贴、社保、公积金、工会经费等。', 2, 'easy', 2.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('single_choice', '预收账款属于什么类型的科目？', JSON_ARRAY('A. 资产类', 'B. 负债类', 'C. 所有者权益类', 'D. 损益类'), 'B', '预收账款是企业预先收取的款项但尚未提供商品或服务，构成企业的现时义务，属于负债类科目。', 2, 'easy', 2.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('single_choice', '长期借款的利息费用在符合资本化条件时应如何处理？', JSON_ARRAY('A. 全部计入当期损益', 'B. 计入资产成本', 'C. 冲减借款本金', 'D. 计入资本公积'), 'B', '为购建固定资产而借入的专门借款，在资产达到预定可使用状态前的利息支出应予以资本化，计入资产成本。', 2, 'medium', 2.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('single_choice', '银行承兑汇票对银行来说属于什么？', JSON_ARRAY('A. 资产', 'B. 负债', 'C. 所有者权益', 'D. 或有负债'), 'D', '银行承兑汇票是银行的表外业务，属于或有负债。当客户不能按时付款时，银行需要代为支付，此时才转化为实际负债。', 2, 'medium', 2.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('single_choice', '递延所得税负债属于什么类型的负债？', JSON_ARRAY('A. 流动负债', 'B. 非流动负债', 'C. 或有负债', 'D. 预计负债'), 'B', '递延所得税负债通常与长期时间性差异相关，属于非流动负债。', 2, 'medium', 2.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('single_choice', '以下哪种情况会导致预计负债的确认？', JSON_ARRAY('A. 签订采购合同', 'B. 产品质量保证', 'C. 收到客户预付款', 'D. 计提折旧'), 'B', '产品质量保证很可能导致未来经济利益的流出且金额能合理估计，应确认为预计负债。签订合同、收预付款、计提折旧不直接产生预计负债。', 2, 'medium', 2.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('single_choice', '应付债券的溢折价应当在什么期间内摊销？', JSON_ARRAY('A. 债券发行时一次性处理', 'B. 债券存续期间', 'C. 债券到期时一次性处理', 'D. 任意期间'), 'B', '应付债券的溢折价应当在债券存续期间内采用实际利率法进行摊销，调整各期的利息费用。', 2, 'hard', 3.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('single_choice', '商业银行同业存放款项属于？', JSON_ARRAY('A. 资产', 'B. 负债', 'C. 权益', 'D. 表外项目'), 'B', '同业存放款项是其他银行存入本行的资金，对本行而言是负债。与之对应，存放同业款项是本行存入其他银行的资金，属于资产。', 2, 'easy', 2.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('single_choice', '以下哪项不是流动负债的确认条件？', JSON_ARRAY('A. 预计在一个正常营业周期内清偿', 'B. 主要为交易目的而持有', 'C. 企业无权自主将清偿推迟至资产负债表日后一年以上', 'D. 偿还金额已经确定'), 'D', '流动负债的三个确认条件与偿还金额是否确定无关。金额不确定的流动负债（如应付账款估计数）也可确认为流动负债。', 2, 'medium', 2.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('single_choice', '企业发生借款费用时，一般借款费用的资本化条件是？', JSON_ARRAY('A. 借款已经发生即可', 'B. 资产支出已经发生且借款费用已经发生', 'C. 只要有借款就可资本化', 'D. 管理层批准即可'), 'B', '一般借款费用资本化需同时满足：(1)资产支出已经发生；(2)借款费用已经发生；(3)为使资产达到预定可使用状态所必要的购建活动已经开始。', 2, 'hard', 3.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('single_choice', '以现金清偿债务时，债务重组利得应计入？', JSON_ARRAY('A. 资本公积', 'B. 营业外收入', 'C. 主营业务收入', 'D. 投资收益'), 'B', '债务人以低于债务账面价值的现金清偿债务时，差额作为债务重组利得计入营业外收入。', 2, 'easy', 2.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('single_choice', '银行吸收存款支付的利息属于？', JSON_ARRAY('A. 营业成本', 'B. 利息支出', 'C. 管理费用', 'D. 财务费用'), 'B', '银行吸收存款支付的利息属于利息支出，是银行最主要的资金成本，在利润表中单独列示为利息支出。', 2, 'easy', 2.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('single_choice', '以下哪项不属于流动负债？', JSON_ARRAY('A. 短期借款', 'B. 应付票据', 'C. 应付债券', 'D. 应交税费'), 'C', '应付债券通常期限在一年以上，属于非流动负债。短期借款、应付票据、应交税费都在一年内偿还，属于流动负债。', 2, 'easy', 2.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('single_choice', '预计负债应当按照什么金额进行初始计量？', JSON_ARRAY('A. 最佳估计数', 'B. 最高可能金额', 'C. 最低可能金额', 'D. 账面价值'), 'A', '预计负债应按履行相关现时义务所需支出的最佳估计数进行初始计量，考虑风险和不确定性后综合确定。', 2, 'medium', 2.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('single_choice', '可转换公司债券在初始确认时应如何处理？', JSON_ARRAY('A. 全部确认为负债', 'B. 全部确认为权益', 'C. 分拆负债成分和权益成分', 'D. 全部确认为金融资产'), 'C', '可转换公司债券属于复合金融工具，应将负债成分（债券本金利息）和权益成分（转股权）进行分拆并分别确认。', 2, 'hard', 3.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('single_choice', '银行拆入资金属于什么性质？', JSON_ARRAY('A. 资产', 'B. 负债', 'C. 所有者权益', 'D. 或有事项'), 'B', '拆入资金是银行从其他金融机构借入的短期资金，属于银行的负债（同业拆入）。', 2, 'easy', 2.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('single_choice', '长期应付款的折现率通常选用什么？', JSON_ARRAY('A. 银行同期存款利率', 'B. 同期银行贷款利率', 'C. 内含利率或同期市场利率', 'D. 任意利率'), 'C', '长期应付款应按公允价值进行初始计量，折现率通常选用内含利率；无法确定内含利率时采用同期市场利率。', 2, 'medium', 2.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW());
INSERT INTO busi_questions (question_type, content, options, correct_answer, analysis, category_id, difficulty, default_score, org_id, org_nm, is_deleted, created_by_id, created_at, updated_at) VALUES
('multiple_choice', '以下哪些属于流动负债？', JSON_ARRAY('A. 短期借款', 'B. 应付账款', 'C. 应交税费', 'D. 长期借款'), JSON_ARRAY('A', 'B', 'C'), '短期借款、应付账款、应交税费都在一年内到期，属于流动负债。长期借款偿还期超过一年，属于非流动负债。', 2, 'easy', 3.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('multiple_choice', '预计负债的确认条件包括？', JSON_ARRAY('A. 该义务是企业承担的现时义务', 'B. 履行该义务很可能导致经济利益流出', 'C. 该义务的金额能够可靠计量', 'D. 该义务已经得到法律确认'), JSON_ARRAY('A', 'B', 'C'), '预计负债的三条件：现时义务、很可能流出、金额可靠计量。法律确认不是确认条件，可能早于法律程序就已确认。', 2, 'easy', 3.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('multiple_choice', '职工薪酬包括？', JSON_ARRAY('A. 工资奖金', 'B. 社会保险费', 'C. 住房公积金', 'D. 工会经费和职工教育经费'), JSON_ARRAY('A', 'B', 'C', 'D'), '四项都属于职工薪酬的范围，体现了企业对职工的全面薪酬义务。', 2, 'easy', 3.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('multiple_choice', '以下哪些属于银行负债？', JSON_ARRAY('A. 客户存款', 'B. 同业存放款项', 'C. 发行债券', 'D. 向央行借款'), JSON_ARRAY('A', 'B', 'C', 'D'), '四项都是银行的负债来源：客户存款是核心负债，同业存放是同行间拆借，债券是主动负债，央行借款是最后贷款人渠道。', 2, 'easy', 3.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('multiple_choice', '以下哪些是借款费用资本化的条件？', JSON_ARRAY('A. 资产支出已经发生', 'B. 借款费用已经发生', 'C. 购建活动已经开始', 'D. 借款合同已签订'), JSON_ARRAY('A', 'B', 'C'), '借款费用资本化需三个条件同时满足。仅签订合同不构成开始资本化的充分条件。', 2, 'medium', 3.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('multiple_choice', '应交税费包括？', JSON_ARRAY('A. 增值税', 'B. 企业所得税', 'C. 印花税', 'D. 个人所得税（代扣代缴）'), JSON_ARRAY('A', 'B', 'C', 'D'), '四项都属于应交税费核算范围。个人所得税虽然是代扣代缴性质，但同样通过应交税费科目核算。', 2, 'easy', 3.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('multiple_choice', '或有负债的披露内容包括？', JSON_ARRAY('A. 或有负债的种类和形成原因', 'B. 经济利益流出不确定性的说明', 'C. 预计产生的财务影响', 'D. 获得补偿的可能性'), JSON_ARRAY('A', 'B', 'C', 'D'), '以上四个方面的信息都需要在财务报表附注中充分披露，使报表使用者了解或有负债的风险状况。', 2, 'medium', 3.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('multiple_choice', '长期借款的利息费用可能计入？', JSON_ARRAY('A. 财务费用', 'B. 在建工程', 'C. 制造费用', 'D. 管理费用'), JSON_ARRAY('A', 'B'), '符合资本化条件的计入在建工程（最终形成固定资产），不符合资本化条件的计入财务费用。一般不计入制造费用或管理费用。', 2, 'medium', 3.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('multiple_choice', '应付票据包括？', JSON_ARRAY('A. 银行承兑汇票', 'B. 商业承兑汇票', 'C. 支票', 'D. 本票'), JSON_ARRAY('A', 'B'), '应付票据包括银行承兑汇票和商业承兑汇票。支票和本票属于其他货币资金或银行存款的范畴。', 2, 'easy', 3.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('multiple_choice', '关于债务重组，以下说法正确的有？', JSON_ARRAY('A. 以现金清偿债务的差额计入营业外收入', 'B. 以非现金资产清偿的差额需区分资产转让损益和债务重组损益', 'C. 债务转为资本的差额计入资本公积', 'D. 修改其他条件的需要按公允价值重新计量'), JSON_ARRAY('A', 'B', 'D'), '债务转为资本时，差额应计入营业外收入（债务重组利得），而非资本公积。资本公积仅核算股份公允价值与面值的差额。', 2, 'hard', 3.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('multiple_choice', '其他应付款包括？', JSON_ARRAY('A. 应付包装物租金', 'B. 存入保证金', 'C. 应付统筹退休金', 'D. 应付货款'), JSON_ARRAY('A', 'B', 'C'), '应付货款属于应付账款。包装物租金、存入保证金、统筹退休金都计入其他应付款。', 2, 'easy', 3.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('multiple_choice', '借款费用包括？', JSON_ARRAY('A. 借款利息', 'B. 债券溢折价摊销', 'C. 借款辅助费用', 'D. 外币借款汇兑差额'), JSON_ARRAY('A', 'B', 'C', 'D'), '四项都属于借款费用的组成部分，在资本化期间符合条件的都应予以资本化。', 2, 'medium', 3.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('multiple_choice', '以下哪些属于银行的主动负债？', JSON_ARRAY('A. 发行金融债券', 'B. 大额可转让存单', 'C. 同业拆入', 'D. 客户活期存款'), JSON_ARRAY('A', 'B', 'C'), '金融债券、大额存单、同业拆入都是银行主动管理的负债工具。客户活期存款属于被动负债，取决于客户存取行为。', 2, 'medium', 3.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('multiple_choice', '关于可转换债券，说法正确的有？', JSON_ARRAY('A. 属于复合金融工具', 'B. 需要分拆负债和权益成分', 'C. 转股权确认为权益', 'D. 全部金额确认为负债'), JSON_ARRAY('A', 'B', 'C'), '可转换债券是复合金融工具，需分拆负债（债券未来现金流现值）和权益（转股权价值），两者分别确认。', 2, 'hard', 3.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('multiple_choice', '负债的特征包括？', JSON_ARRAY('A. 由过去的交易或事项形成', 'B. 预期会导致经济利益流出', 'C. 是企业承担的现时义务', 'D. 一定能可靠计量'), JSON_ARRAY('A', 'B', 'C'), '负债的三个基本特征。可靠计量是确认条件而非负债的定义特征，有些负债（如预计负债）金额具有不确定性。', 2, 'medium', 3.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('multiple_choice', '以下哪些情况会形成递延所得税负债？', JSON_ARRAY('A. 固定资产加速折旧', 'B. 交易性金融资产公允价值上升', 'C. 计提资产减值准备', 'D. 预提产品质量保证费用'), JSON_ARRAY('A', 'B'), '会计上少计费用/多计收入时产生应纳税暂时性差异，形成递延所得税负债。加速折旧和公允价值上升符合这种情况。减值和预提费用相反，产生递延所得税资产。', 2, 'hard', 3.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('multiple_choice', '银行流动性负债管理工具包括？', JSON_ARRAY('A. 存款准备金', 'B. 同业拆借', 'C. 回购协议', 'D. 央行再贷款'), JSON_ARRAY('A', 'B', 'C', 'D'), '四种工具都是银行常用的流动性管理手段，涵盖事前预防（准备金）和事后补救（拆借、回购、再贷款）。', 2, 'medium', 3.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('multiple_choice', '以下哪些属于结算性负债？', JSON_ARRAY('A. 应付票据', 'B. 应付账款', 'C. 预收账款', 'D. 应付职工薪酬'), JSON_ARRAY('A', 'B', 'C'), '应付票据、应付账款、预收账款都产生于日常经营活动中的结算行为。应付职工薪酬属于分配性负债。', 2, 'easy', 3.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('multiple_choice', '关于借款费用，以下表述正确的有？', JSON_ARRAY('A. 专门借款利息全部资本化', 'B. 一般借款需计算累计支出加权平均数', 'C. 暂停资本化期间借款费用计入当期损益', 'D. 资产达到预定可使用状态后停止资本化'), JSON_ARRAY('B', 'C', 'D'), '专门借款利息需扣减未动用部分的投资收益后资本化，并非全部资本化。其他三项表述正确。', 2, 'hard', 3.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('multiple_choice', '与资产相关的政府补助确认为递延收益后，后续处理方式有？', JSON_ARRAY('A. 在资产使用寿命内平均分配', 'B. 一次性计入当期损益', 'C. 冲减资产账面价值', 'D. 计入资本公积'), JSON_ARRAY('A', 'C'), '与资产相关的政府补助有两种处理方法：(1)总额法——确认为递延收益后分期计入损益；(2)净额法——直接冲减资产账面价值。', 2, 'medium', 3.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW());
INSERT INTO busi_questions (question_type, content, options, correct_answer, analysis, category_id, difficulty, default_score, org_id, org_nm, is_deleted, created_by_id, created_at, updated_at) VALUES
('true_false', '客户存款是银行最主要的负债来源。', JSON_ARRAY(), '对', '对商业银行而言，吸收存款是最传统和最主要的资金来源，存款类负债通常占总负债的70%以上。', 2, 'easy', 2.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('true_false', '所有负债都需要在资产负债表中确认。', JSON_ARRAY(), '错', '或有负债如果不符合确认条件（不是很可能导致经济利益流出或金额不能可靠计量），则不需要在表内确认，只在附注中披露即可。', 2, 'easy', 2.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('true_false', '预计负债的最佳估计数应当是最大可能金额。', JSON_ARRAY(), '错', '预计负债的最佳估计数应当是各种可能结果按其概率加权计算的平均值，而非简单的最大可能值。', 2, 'medium', 2.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('true_false', '发行债券的溢价收入应一次性计入当期收益。', JSON_ARRAY(), '错', '债券溢价应当在债券存续期内按实际利率法分期摊销，冲减各期的利息费用，不能一次性确认收益。', 2, 'easy', 2.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('true_false', '借款费用资本化期间包括因不可抗力中断的期间。', JSON_ARRAY(), '错', '如果购建活动发生非正常中断且中断时间连续超过3个月，应当暂停借款费用的资本化，将相关借款费用计入当期损益。不可抗力造成的中断即符合此条件。', 2, 'medium', 2.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('true_false', '应付债券的利息调整（溢折价）应采用实际利率法摊销。', JSON_ARRAY(), '对', '根据会计准则，应付债券的溢折价（利息调整）必须采用实际利率法在债券存续期间内进行摊销。', 2, 'easy', 2.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('true_false', '递延收益属于负债类科目。', JSON_ARRAY(), '对', '递延收益是尚待确认的收入或收益，企业收到但尚未满足确认条件的款项，属于负债。如政府补助先确认为递延收益。', 2, 'medium', 2.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('true_false', '银行的或有负债不需要在财务报表中披露。', JSON_ARRAY(), '错', '或有负债即使不符合确认条件，也应当在财务报表附注中披露其种类、形成原因、预计影响等内容，满足信息披露要求。', 2, 'easy', 2.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('true_false', '一般借款费用的资本化金额按累计资产支出加权平均数乘以资本化率计算。', JSON_ARRAY(), '对', '一般借款费用资本化金额=累计资产支出超过专门借款的部分的加权平均数×一般借款的资本化率。', 2, 'hard', 3.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('true_false', '企业的应交税费包括代扣代缴的个人所得税。', JSON_ARRAY(), '对', '企业作为个人所得税的扣缴义务人，代扣的个人所得税在缴纳入库前构成企业的应交税费。', 2, 'easy', 2.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('true_false', '长期负债在到期日前一年内应重分类为流动负债。', JSON_ARRAY(), '对', '对于在资产负债表日起一年内到期的长期负债，除非企业有自主展期能力，否则应将其重分类为一年内到期的非流动负债（流动负债）。', 2, 'medium', 2.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('true_false', '债务重组收益应当计入资本公积。', JSON_ARRAY(), '错', '债务重组收益（债务重组利得）应当计入营业外收入，而非资本公积。这是会计准则的明确规定。', 2, 'medium', 2.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('true_false', '银行吸收存款的利率完全由银行自行决定。', JSON_ARRAY(), '错', '银行存款利率受央行基准利率和市场利率定价自律机制的约束，并非完全自由定价。贷款利率已实现市场化（LPR定价）。', 2, 'easy', 2.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('true_false', '产品质量保证构成企业的预计负债。', JSON_ARRAY(), '对', '提供产品质量保证是企业的一项推定义务，相关支出很可能发生且金额能合理估计，应确认为预计负债。', 2, 'easy', 2.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('true_false', '股票股利属于企业的负债。', JSON_ARRAY(), '错', '股票股利是利润分配的一种形式，属于所有者权益内部的变动，不构成负债。应付现金股利才属于负债。', 2, 'medium', 2.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('true_false', '所有预计负债都可以税前扣除。', JSON_ARRAY(), '错', '部分预计负债（如产品质保费、未决诉讼预计赔偿）在计提时不能税前扣除，只有在实际发生时才能扣除，从而产生递延所得税资产。', 2, 'hard', 3.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('true_false', '银行理财产品的募集资金属于银行的表内负债。', JSON_ARRAY(), '错', '大多数银行理财产品属于表外业务（非保本型），资金不计入银行资产负债表。保本型理财产品例外。', 2, 'medium', 2.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('true_false', '借款费用资本化的前提条件是资产必须达到预定可使用状态。', JSON_ARRAY(), '错', '借款费用开始资本化的条件是资产支出和借款费用均已经发生，且购建活动已经开始。达到预定可使用状态是停止资本化的条件，而非开始条件。', 2, 'medium', 2.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('true_false', '应付账款一般按发票金额入账，不需要考虑现金折扣。', JSON_ARRAY(), '错', '应付账款应按扣除商业折扣但不扣除现金折扣的金额入账（总价法）。实际获得现金折扣时冲减财务费用。', 2, 'medium', 2.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('true_false', '银行核心一级资本属于负债性质。', JSON_ARRAY(), '错', '核心一级资本（实收资本、资本公积、盈余公积、未分配利润等）属于所有者权益，不属于负债。负债和所有者权益是资产负债表的两个不同类别。', 2, 'easy', 2.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW());
INSERT INTO busi_questions (question_type, content, options, correct_answer, analysis, category_id, difficulty, default_score, org_id, org_nm, is_deleted, created_by_id, created_at, updated_at) VALUES
('fill_blank', '预计负债应当按照履行现时义务所需支出的______进行初始计量。', JSON_ARRAY(), '最佳估计数', '最佳估计数考虑了各种可能结果的概率加权，而非简单的最大值或最小值。', 2, 'easy', 3.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('fill_blank', '银行最主要的负债来源是______。', JSON_ARRAY(), '客户存款', '存款是商业银行最传统、最主要的资金来源，构成银行负债的主体。', 2, 'easy', 3.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('fill_blank', '借款费用包括利息、溢折价摊销、辅助费用和______。', JSON_ARRAY(), '外币借款汇兑差额', '四种借款费用类型，汇兑差额容易被忽略但同样属于借款费用的范畴。', 2, 'medium', 3.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('fill_blank', '可转换公司债券属于______金融工具。', JSON_ARRAY(), '复合', '可转换公司债券兼具负债（债券）和权益（转股权）双重特性，属于复合金融工具，需要分拆确认。', 2, 'medium', 3.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('fill_blank', '短期借款的偿还期限在______以内。', JSON_ARRAY(), '一年', '偿还期限在一年（含一年）以内的借款属于流动负债中的短期借款。', 2, 'easy', 3.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('fill_blank', '或有事项可能形成资产和______两种结果。', JSON_ARRAY(), '预计负债', '或有事项可能导致或有资产（如未决诉讼可能获得赔偿）和或有负债/预计负债（如产品质量保证义务）。', 2, 'easy', 3.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('fill_blank', '应付债券的折价在资产负债表中作为______的减项列示。', JSON_ARRAY(), '应付债券', '应付债券折价是应付债券的抵减项，发行时借记应付债券-利息调整，期末应付债券账面价值=面值-折价（或+溢价）。', 2, 'medium', 3.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('fill_blank', '从______日起，一年内到期的长期负债应重分类为流动负债。', JSON_ARRAY(), '资产负债表', '判断是否重分类的基准日是资产负债表日。如果从资产负债表日起一年内到期，应重分类。', 2, 'easy', 3.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('fill_blank', '银行法定存款准备金率由______制定。', JSON_ARRAY(), '中国人民银行', '央行通过调整法定存款准备金率来调节货币信贷总量，是货币政策三大工具之一。', 2, 'easy', 3.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('fill_blank', '长期借款利息资本化金额的计算基数是______。', JSON_ARRAY(), '累计资产支出加权平均数', '一般借款资本化金额=累计资产支出超过专门借款部分的加权平均数×资本化率。专门借款以实际利息费用减投资收益计算。', 2, 'hard', 4.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('fill_blank', '借款费用开始资本化需同时满足三个条件：资产支出已发生、借款费用已发生和______。', JSON_ARRAY(), '购建活动已经开始', '三个条件缺一不可。仅签订合同或仅获批贷款都不满足开始资本化的条件。', 2, 'medium', 3.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('fill_blank', '银行同业存放款项在银行的资产负债表上属于______。', JSON_ARRAY(), '负债', '同业存放是他行存入本行的资金，本行负有偿还义务，属于负债。相反存放同业属于资产。', 2, 'easy', 3.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('fill_blank', '递延收益在资产负债表上列示在______项目下。', JSON_ARRAY(), '其他非流动负债', '递延收益属于尚未确认的收入，在资产负债表上通常列示在其他非流动负债项目下。', 2, 'medium', 3.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('fill_blank', '债务重组中债权人作出的让步，债务人应确认为______。', JSON_ARRAY(), '营业外收入', '债务重组利得属于非经常性损益，应计入营业外收入，而不应计入主营业务收入或投资收益。', 2, 'easy', 3.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('fill_blank', '预计负债与或有负债的区别在于：预计负债的偿付义务是______。', JSON_ARRAY(), '很可能', '预计负债要求'很可能'(概率>50%)导致经济利益流出，而或有负债则是'可能'(5%-50%)或金额不能可靠计量。', 2, 'medium', 3.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('fill_blank', '金融负债按______进行初始计量。', JSON_ARRAY(), '公允价值', '金融负债初始确认时按公允价值计量，交易费用一般在初始确认时计入损益（交易性金融负债）或初始成本（其他金融负债）。', 2, 'medium', 3.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('fill_blank', '应付债券的实际利率应当在______时确定。', JSON_ARRAY(), '初始确认', '实际利率应当在初始确认时根据预计未来现金流量确定，后续期间保持不变，用于计算各期的实际利息费用。', 2, 'hard', 4.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('fill_blank', '银行承兑汇票对承兑银行而言是______。', JSON_ARRAY(), '或有负债', '银行承兑汇票属于表外业务，汇票到期时若出票人不能足额付款，银行才需垫款，此时才转化为表内负债。', 2, 'easy', 3.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('fill_blank', '产品质量保证构成企业的______负债。', JSON_ARRAY(), '预计', '产品质保属于推定义务，相关支出很可能发生，应确认为预计负债而非一般应付款。', 2, 'easy', 3.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('fill_blank', '递延所得税负债产生于______暂时性差异。', JSON_ARRAY(), '应纳税', '当资产的账面价值大于计税基础或负债的账面价值小于计税基础时，形成应纳税暂时性差异，确认递延所得税负债。', 2, 'hard', 4.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW());
INSERT INTO busi_questions (question_type, content, options, correct_answer, analysis, category_id, difficulty, default_score, org_id, org_nm, is_deleted, created_by_id, created_at, updated_at) VALUES
('short_answer', '请简述负债的定义及确认条件。', JSON_ARRAY(), '负债是指企业过去的交易或事项形成的、预期会导致经济利益流出的现时义务。确认条件：(1)与该义务有关的经济利益很可能流出企业；(2)未来流出的经济利益的金额能够可靠地计量。', '负债的两大确认条件缺一不可。', 2, 'easy', 5.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('short_answer', '流动负债和非流动负债的划分标准是什么？', JSON_ARRAY(), '流动负债需满足下列条件之一：(1)预计在一个正常营业周期中清偿；(2)主要为交易目的而持有；(3)自资产负债表日起一年内到期应予以清偿；(4)企业无权自主地将清偿推迟至资产负债表日后一年以上。其他负债为非流动负债。', '四个条件是"或"的关系，满足任一即为流动负债。', 2, 'easy', 5.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('short_answer', '请解释预计负债与或有负债的区别。', JSON_ARRAY(), '预计负债：现时义务，很可能(>50%)导致流出且金额能可靠计量，需在表内确认。或有负债：(1)潜在义务，是否存在取决于未来不确定事项；或(2)现时义务但不满足确认条件（不是很可能或金额不能计量），只需附注披露。', '关键区别在于"很可能"这个概率门槛。', 2, 'medium', 5.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('short_answer', '请说明可转换公司债券的会计处理要点。', JSON_ARRAY(), '(1)发行时：分拆负债成分（按不附转股权的同类债券市场利率折现）和权益成分（差额=发行价-负债成分公允价值）；(2)后续：负债成分按实际利率法计提利息并摊销折溢价；(3)转股时：终止确认负债成分和权益成分，差额计入资本公积。', '分拆计量是复合金融工具的核心。', 2, 'hard', 6.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('short_answer', '请说明银行负债的主要类型和管理要求。', JSON_ARRAY(), '主要类型：(1)存款类——活期、定期、储蓄存款等，是最主要来源；(2)借款类——同业拆借、央行借款、回购协议；(3)债券类——金融债券、大额存单；(4)结算类——应付票据、汇出汇款。管理要求：保持适当流动性、控制融资成本、期限结构匹配、合规经营。', '存款立行是银行经营的基石。', 2, 'medium', 5.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('short_answer', '请简述借款费用资本化的开始、暂停和停止条件。', JSON_ARRAY(), '开始：同时满足(1)资产支出已发生；(2)借款费用已发生；(3)购建活动已开始。暂停：非正常中断连续超过3个月。停止：资产达到预定可使用或可销售状态时。', '资本化的"开始"和"停止"时点至关重要。', 2, 'medium', 5.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('short_answer', '请分析债务重组的几种方式及其会计处理差异。', JSON_ARRAY(), '(1)以资产清偿——转让资产公允价值与账面价值的差额计入资产处置损益，债务额与资产公允价值的差额计入营业外收入；(2)债务转为资本——股权公允价值与面值差额入资本公积，债务额与股权公允价值差额入营业外收入；(3)修改其他债务条件——按修改后债权的公允价值确认。', '债务重组损益与资产处置损益需要分别核算。', 2, 'hard', 6.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('short_answer', '请解释递延所得税负债的形成原因。', JSON_ARRAY(), '形成原因：应纳税暂时性差异。常见例子：(1)固定资产加速折旧——税务折旧比会计折旧快，会计资产账面价值>计税基础；(2)交易性金融资产公允价值上升产生账面收益但未实现；(3)长期股权投资权益法确认收益但被投资方未分红。这些都会导致当期应纳税所得额小于会计利润，形成未来纳税义务。', '递延所得税负债代表将来需要多交的所得税。', 2, 'medium', 5.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('short_answer', '请简述或有事项的会计处理原则。', JSON_ARRAY(), '处理原则：(1)或有资产——除非基本确定(>95%)能收到，否则不确认，只可能披露；(2)预计负债——很可能(>50%)且可靠计量时确认，并在报表附注中披露；(3)或有负债——不符合确认条件时只披露不确认；(4)预期可获得的补偿——基本确定能收到时单独确认为资产，不超过确认的预计负债金额。', '区分"很可能"和"可能"是关键。', 2, 'medium', 5.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('short_answer', '请分析银行存款保险制度的要点。', JSON_ARRAY(), '要点：(1)投保机构——所有吸收存款的银行业金融机构强制投保；(2)保费缴纳——按差别费率缴纳保费；(3)保障范围——人民币和外币存款均在保障范围内；(4)最高偿付限额——50万元人民币；(5)基金来源——投保机构缴纳的保费+基金投资收益+其他合法收入。会计上保费支出计入管理费用或业务及管理费。', '存款保险制度的50万限额是储户保护的安全线。', 2, 'easy', 5.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('short_answer', '请解释金融负债与权益工具的区别。', JSON_ARRAY(), '判断标准：(1)是否存在无条件避免交付现金或其他金融资产的合同义务——有则为金融负债，无则为权益工具；(2)是否通过固定数量的自身权益工具结算——非固定数量为金融负债。典型例子：普通股是权益工具，优先股（强制付息）是金融负债，永续债视条款而定。', '实质重于形式，不能仅以名称判断。', 2, 'hard', 6.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('short_answer', '请说明应付职工薪酬的构成及确认原则。', JSON_ARRAY(), '构成：(1)短期薪酬——工资、奖金、津贴、社保公积金、工会经费、职工教育经费等；(2)离职后福利——设定提存计划（基本养老保险）；(3)辞退福利——解除劳动关系补偿；(4)其他长期福利——长期带薪缺勤等。确认原则：在职工提供服务的会计期间确认为负债，同时根据受益对象计入资产成本或当期损益。', '辞退福利的确认时点是两者孰早：正式提出或确认支付。', 2, 'easy', 5.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('short_answer', '请简述银行同业负债的主要形式和监管要求。', JSON_ARRAY(), '形式：(1)同业拆借——期限短（1天到1年），用于临时性头寸调剂；(2)同业存放——他行存入的结算资金；(3)回购协议——卖出证券并约定日后回购，实质为质押融资。监管要求：同业负债占总负债比例不超过1/3，单家同业融资不超过一级资本净额的50%，不得通过同业科目隐匿信贷资产。', '同业负债管理不当可能引发系统性风险。', 2, 'medium', 5.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('short_answer', '请分析负债的流动性风险及管理策略。', JSON_ARRAY(), '风险：资金来源不稳定（如活期存款随时可提取）导致无法及时偿还到期债务。管理策略：(1)期限匹配——资产和负债的期限结构尽量匹配，避免短借长贷；(2)核心存款管理——稳定低成本的核心存款比例；(3)备付金管理——保持充足的头寸；(4)应急预案——建立紧急融资渠道（央行再贷款、同业拆借额度等）。', '资产负债期限错配是银行流动性风险的根本来源。', 2, 'hard', 6.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('short_answer', '请解释以公允价值计量的金融负债及其会计处理。', JSON_ARRAY(), '分类：(1)交易性金融负债——为近期出售或回购而持有，公允价值变动计入当期损益；(2)指定为以公允价值计量的金融负债——减少会计错配或基于风险管理策略。处理要点：初始按公允价值计量，交易费用计入损益；后续公允价值变动计入公允价值变动损益；自身信用风险变动计入其他综合收益。', '自身信用风险变动计入OCI是重要特殊规定。', 2, 'medium', 5.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('short_answer', '请说明一般借款与专门借款资本化金额的计算方法区别。', JSON_ARRAY(), '专门借款：资本化金额=资本化期间的实际利息费用-未动用借款的临时投资收益（或存款利息）。一般借款：资本化金额=累计资产支出超过专门借款部分的加权平均数×一般借款的资本化率（加权平均利率）。专门借款的资本化计算更为简单直接。', '专门借款以实际发生额为基础，一般借款需加权计算。', 2, 'medium', 5.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('short_answer', '请解释负债在合并报表中的抵销原则。', JSON_ARRAY(), '原则：(1)母子公司之间以及子公司相互之间的债权债务项目应当相互抵销；(2)内部债券投资与应付债券抵销时，差额计入投资收益或财务费用；(3)内部应收应付账款抵销时，对应计提的坏账准备也要抵销；(4)未实现内部交易损益涉及的递延所得税影响也应抵销。', '合并抵销的目的是消除内部交易对合并报表的影响。', 2, 'hard', 6.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('short_answer', '请简述资产负债表日后事项对负债的影响。', JSON_ARRAY(), '调整事项（资产负债表日已存在）：如诉讼结案确认金额与原估计不同，应调整原预计负债金额。非调整事项（资产负债表日后新发生）：如发行债券、举借大额借款，只需附注披露。区分原则：事项在资产负债表日是否已经存在。', '资产表日后事项的调整与否取决于事项的归属期间。', 2, 'easy', 5.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('short_answer', '请说明银行表外负债的风险和披露要求。', JSON_ARRAY(), '表外负债类型：银行承兑汇票、信用证、保函、贷款承诺、未决诉讼等。风险：(1)转化为表内负债的可能；(2)杠杆效应——较少的保证金撬动大额业务。披露要求：在财务报表附注中披露表外项目的余额、性质、风险敞口、风险管理措施，以及可能对财务状况产生的影响。', '表外不是无风险，风险披露同样重要。', 2, 'easy', 5.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('short_answer', '请分析应付债券实际利率法的计算原理及应用。', JSON_ARRAY(), '原理：实际利率法是根据金融负债的实际利率计算各期利息费用的方法。实际利率=将未来现金流量折现为当前账面价值的折现率。步骤：(1)确定预计未来现金流量（本金+利息）；(2)确定初始账面价值；(3)计算实际利率；(4)每期利息费用=期初账面余额×实际利率；(5)摊销额=面值×票面利率-利息费用。', '实际利率法确保了各期利息费用的准确匹配。', 2, 'medium', 5.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW());
INSERT INTO busi_questions (question_type, content, options, correct_answer, analysis, category_id, difficulty, default_score, org_id, org_nm, is_deleted, created_by_id, created_at, updated_at) VALUES
('single_choice', '商业银行内部控制的首要目标是？', JSON_ARRAY('A. 盈利最大化', 'B. 保证国家法律法规和规章制度的贯彻执行', 'C. 提高经营效率', 'D. 扩大市场份额'), 'B', '内部控制的首要目标是保证国家法律法规、金融监管规章和银行内部规章制度的贯彻执行，合规是银行的生命线。', 3, 'easy', 2.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('single_choice', '银行操作风险管理的三大工具不包括？', JSON_ARRAY('A. 风险与控制自评估(RCSA)', 'B. 关键风险指标(KRI)', 'C. 损失数据收集(LDC)', 'D. 信用评级模型'), 'D', '操作风险三大工具：RCSA、KRI、LDC。信用评级模型属于信用风险管理工具。', 3, 'medium', 2.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('single_choice', '商业银行流动性风险监管指标中，流动性覆盖率(LCR)的最低要求是？', JSON_ARRAY('A. 不低于25%', 'B. 不低于50%', 'C. 不低于100%', 'D. 不低于150%'), 'C', '流动性覆盖率(LCR)=优质流动性资产储备/未来30天现金净流出量，监管要求不低于100%。', 3, 'medium', 2.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('single_choice', '商业银行的核心一级资本充足率最低要求是？', JSON_ARRAY('A. 4%', 'B. 5%', 'C. 6%', 'D. 8%'), 'B', '根据巴塞尔Ⅲ和银保监会规定，核心一级资本充足率不低于5%，一级资本充足率不低于6%，资本充足率不低于8%。', 3, 'easy', 2.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('single_choice', '银行反洗钱工作中，大额交易报告的标准是？', JSON_ARRAY('A. 单笔5万元以上', 'B. 单笔20万元以上', 'C. 单笔50万元以上', 'D. 单笔100万元以上'), 'B', '根据《金融机构大额交易和可疑交易报告管理办法》，单笔或当日累计20万元以上的现金交易需要报告。', 3, 'medium', 2.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('single_choice', '以下哪项不是商业银行的"三道防线"？', JSON_ARRAY('A. 业务部门和经营机构', 'B. 风险管理部门', 'C. 内部审计部门', 'D. 外部监管机构'), 'D', '三道防线：第一道——业务部门（一线风险识别）；第二道——风险管理和合规部门（独立监控）；第三道——内部审计（独立评价）。外部监管不属于内部防线。', 3, 'easy', 2.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('single_choice', '银行客户身份识别制度中，受益所有人识别标准是持股比例超过？', JSON_ARRAY('A. 20%', 'B. 25%', 'C. 30%', 'D. 50%'), 'B', '根据反洗钱规定，直接或间接拥有超过25%股权或表决权的自然人应当识别为受益所有人。', 3, 'hard', 3.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('single_choice', '商业银行并表管理的要求中，以下哪项说法正确？', JSON_ARRAY('A. 只管理表内风险', 'B. 只管理银行自身风险', 'C. 对全部表内外、境内外、本外币业务进行全面风险管理', 'D. 只对信贷风险进行管理'), 'C', '商业银行应当建立全面的风险管理体系，对全部表内外、境内外、本外币业务和各类风险进行全面并表管理。', 3, 'easy', 2.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('single_choice', '贷款集中度风险监管中，单一集团客户授信集中度不得高于？', JSON_ARRAY('A. 10%', 'B. 15%', 'C. 25%', 'D. 50%'), 'B', '根据监管要求，单一集团客户授信集中度为最大一家集团客户授信总额与资本净额之比，不应高于15%。', 3, 'medium', 2.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('single_choice', '银行从业人员行为规范中，以下哪项是正确的？', JSON_ARRAY('A. 可以利用内幕信息进行个人投资', 'B. 可以将客户信息告知亲属', 'C. 应当遵守保密义务', 'D. 可以在同业兼职不受限制'), 'C', '银行从业人员必须遵守保密义务，不得泄露客户信息，不得利用内幕信息交易，未经批准不得在外兼职。', 3, 'easy', 2.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('single_choice', '信贷业务"三查"制度指的是？', JSON_ARRAY('A. 贷前调查、贷中审查、贷后检查', 'B. 查资质、查信用、查担保', 'C. 查收入、查资产、查负债', 'D. 查用途、查期限、查利率'), 'A', '信贷三查制度：贷前调查（了解客户）、贷中审查（独立审批）、贷后检查（持续监控），是信贷管理的基础制度。', 3, 'easy', 2.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('single_choice', '商业银行杠杆率的最低要求是？', JSON_ARRAY('A. 3%', 'B. 4%', 'C. 5%', 'D. 6%'), 'B', '根据巴塞尔Ⅲ，杠杆率（一级资本/表内外总资产风险暴露）最低要求为4%，作为资本充足率指标的补充。', 3, 'medium', 2.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('single_choice', '不良贷款的认定标准中，"逾期"是指超过多少天？', JSON_ARRAY('A. 30天', 'B. 60天', 'C. 90天', 'D. 180天'), 'C', '根据监管要求，贷款本金或利息逾期超过90天应至少划分为次级类，纳入不良贷款管理。', 3, 'easy', 2.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('single_choice', '商业银行计提的贷款损失准备与不良贷款余额之比称为？', JSON_ARRAY('A. 资本充足率', 'B. 拨备覆盖率', 'C. 流动性比率', 'D. 杠杆率'), 'B', '拨备覆盖率=贷款损失准备/不良贷款余额，反映了银行抵御信用风险的能力，监管要求不低于150%。', 3, 'easy', 2.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('single_choice', '以下哪项不是巴塞尔协议三大支柱？', JSON_ARRAY('A. 最低资本要求', 'B. 监督检查', 'C. 市场约束', 'D. 盈利能力评估'), 'D', '巴塞尔协议三大支柱：最低资本要求（第一支柱）、监督检查（第二支柱）、市场约束（第三支柱）。不包括盈利能力评估。', 3, 'medium', 2.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('single_choice', '商业银行内部审计的独立性主要体现在？', JSON_ARRAY('A. 审计部门设在财务部下', 'B. 直接向董事会或监事会报告', 'C. 由行长直接领导', 'D. 与业务部门合署办公'), 'B', '内部审计的独立性要求其直接向董事会或监事会报告工作，不应设在经营层下，以避免利益冲突。', 3, 'easy', 2.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('single_choice', '银行关联交易管理中，重大关联交易应当由？', JSON_ARRAY('A. 行长审批', 'B. 风险管理部门审批', 'C. 董事会审批', 'D. 股东大会审批'), 'C', '根据《商业银行关联交易管理办法》，重大关联交易应当由董事会关联交易控制委员会审查后提交董事会批准。', 3, 'medium', 2.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('single_choice', '以下哪项属于银行操作风险事件？', JSON_ARRAY('A. 客户违约', 'B. 系统故障导致交易中断', 'C. 利率变动导致债券贬值', 'D. 客户流失'), 'B', '系统故障属于操作风险中的系统风险类别。客户违约是信用风险，利率变动是市场风险，客户流失是经营风险。', 3, 'easy', 2.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('single_choice', '商业银行应当多久开展一次全面的压力测试？', JSON_ARRAY('A. 每月', 'B. 每季度', 'C. 每年至少一次', 'D. 每三年'), 'C', '根据监管要求，商业银行应当至少每年开展一次全面的压力测试，评估极端不利情况下的风险承受能力。', 3, 'medium', 2.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('single_choice', '银行理财产品的销售适当性原则要求？', JSON_ARRAY('A. 向所有人销售任何产品', 'B. 向风险承受能力匹配的客户销售与其匹配的产品', 'C. 只向VIP客户销售', 'D. 只销售保本产品'), 'B', '销售适当性原则要求银行将合适的产品销售给合适的客户，评估客户的风险承受能力并进行产品风险匹配。', 3, 'easy', 2.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW());
INSERT INTO busi_questions (question_type, content, options, correct_answer, analysis, category_id, difficulty, default_score, org_id, org_nm, is_deleted, created_by_id, created_at, updated_at) VALUES
('multiple_choice', '商业银行风险管理的三道防线包括？', JSON_ARRAY('A. 业务部门和经营机构', 'B. 风险管理和合规部门', 'C. 内部审计部门', 'D. 监事会'), JSON_ARRAY('A', 'B', 'C'), '三道防线：一线业务部门、二线风险合规部门、三线内部审计。监事会属于公司治理层面，不属于三道防线的定义范畴。', 3, 'easy', 3.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('multiple_choice', '巴塞尔协议Ⅲ对银行资本的要求包括？', JSON_ARRAY('A. 最低资本要求', 'B. 资本留存缓冲', 'C. 逆周期资本缓冲', 'D. 系统重要性银行附加资本'), JSON_ARRAY('A', 'B', 'C', 'D'), '巴塞尔Ⅲ建立了多层次的资本要求体系，包括以上四个层次，显著提高了银行资本的质量和数量要求。', 3, 'medium', 3.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('multiple_choice', '银行反洗钱制度的主要内容有？', JSON_ARRAY('A. 客户身份识别制度', 'B. 大额交易和可疑交易报告制度', 'C. 客户身份资料和交易记录保存制度', 'D. 反洗钱培训和宣传制度'), JSON_ARRAY('A', 'B', 'C', 'D'), '四项都是反洗钱制度的核心内容，构成了银行反洗钱管理的完整体系。', 3, 'easy', 3.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('multiple_choice', '以下哪些属于银行的市场风险管理工具？', JSON_ARRAY('A. 久期分析', 'B. 风险价值(VaR)', 'C. 压力测试', 'D. 敞口限额管理'), JSON_ARRAY('A', 'B', 'C', 'D'), '四种都是市场风险的管理工具，涵盖从日常敞口限额到极端情景分析的全方位管理。', 3, 'medium', 3.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('multiple_choice', '商业银行资本充足的监管指标包括？', JSON_ARRAY('A. 核心一级资本充足率≥5%', 'B. 一级资本充足率≥6%', 'C. 资本充足率≥8%', 'D. 杠杆率≥4%'), JSON_ARRAY('A', 'B', 'C', 'D'), '这四项构成银行资本充足水平的全面监管标准，从不同维度约束银行的杠杆水平。', 3, 'easy', 3.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('multiple_choice', '信贷管理的"三查"制度包括？', JSON_ARRAY('A. 贷前调查', 'B. 贷中审查', 'C. 贷后检查', 'D. 贷后追偿'), JSON_ARRAY('A', 'B', 'C'), '三查制度：贷前调查（客户准入）、贷中审查（独立审批）、贷后检查（风险监控）。贷后追偿属于不良贷款的处置环节。', 3, 'easy', 3.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('multiple_choice', '银行内部控制的目标包括？', JSON_ARRAY('A. 保证法律法规的贯彻执行', 'B. 保证银行发展战略和经营目标的实现', 'C. 保证风险管理体系的有效性', 'D. 保证业务记录和财务信息的真实完整'), JSON_ARRAY('A', 'B', 'C', 'D'), '四项都是内部控制的四大目标，全面覆盖合规、经营、风险和信息四个维度。', 3, 'medium', 3.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('multiple_choice', '商业银行流动性风险监管指标包括？', JSON_ARRAY('A. 流动性覆盖率(LCR)', 'B. 净稳定资金比例(NSFR)', 'C. 流动性比例', 'D. 核心负债依存度'), JSON_ARRAY('A', 'B', 'C', 'D'), '四项都是流动性风险的监管指标。LCR关注短期，NSFR关注中长期结构稳定，流动性比例衡量即期，核心负债依存度衡量负债稳定性。', 3, 'hard', 3.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('multiple_choice', '银行操作风险的类型包括？', JSON_ARRAY('A. 内部欺诈', 'B. 外部欺诈', 'C. 系统故障', 'D. 客户信用违约'), JSON_ARRAY('A', 'B', 'C'), '内部欺诈、外部欺诈、系统故障是操作风险的七种类型之三。客户信用违约属于信用风险，不是操作风险。', 3, 'medium', 3.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('multiple_choice', '银行从业人员应遵守的职业道德包括？', JSON_ARRAY('A. 诚实守信', 'B. 廉洁自律', 'C. 保护客户隐私', 'D. 可以兼职不受限'), JSON_ARRAY('A', 'B', 'C'), '诚信、自律、保密是基本职业道德。兼职需经批准，不得在与本行有利益冲突的企业兼职。', 3, 'easy', 3.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('multiple_choice', '商业银行的监管评级要素包括？', JSON_ARRAY('A. 资本充足状况', 'B. 资产质量状况', 'C. 管理状况', 'D. 盈利状况'), JSON_ARRAY('A', 'B', 'C', 'D'), 'CAMELS评级体系涵盖资本、资产质量、管理、盈利、流动性和市场风险敏感度六个方面。', 3, 'medium', 3.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('multiple_choice', '银行关联方包括？', JSON_ARRAY('A. 董事、监事和高级管理人员', 'B. 持股5%以上的股东', 'C. 关联法人', 'D. 所有客户'), JSON_ARRAY('A', 'B', 'C'), '关联方包括自然人关联方（董监高及其近亲属）和法人关联方（关联企业）。一般客户不属于关联方。', 3, 'easy', 3.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('multiple_choice', '以下哪些属于银行的表外业务？', JSON_ARRAY('A. 银行承兑汇票', 'B. 信用证', 'C. 贷款承诺', 'D. 委托贷款'), JSON_ARRAY('A', 'B', 'C', 'D'), '四项都属于表外业务，银行不承担直接的信用风险敞口（委托贷款完全由委托人承担风险），或者属于或有项目。', 3, 'medium', 3.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('multiple_choice', '银行压力测试的常见情景包括？', JSON_ARRAY('A. 宏观经济大幅下滑', 'B. 房地产价格大幅下跌', 'C. 利率急剧上升', 'D. 人民币大幅贬值'), JSON_ARRAY('A', 'B', 'C', 'D'), '四种情景都是压力测试的常见假设，测试银行在极端不利条件下的风险承受能力。', 3, 'easy', 3.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('multiple_choice', '关于银行合规管理，以下说法正确的有？', JSON_ARRAY('A. 合规是全员责任', 'B. 合规从高层做起', 'C. 合规创造价值', 'D. 合规只是合规部门的事'), JSON_ARRAY('A', 'B', 'C'), '合规是银行每位员工的责任，需要由董事会和高级管理层率先垂范。良好的合规管理可以避免处罚和声誉损失，间接创造价值。', 3, 'medium', 3.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('multiple_choice', '以下哪些属于银行的主要监管法规？', JSON_ARRAY('A. 《商业银行法》', 'B. 《银行业监督管理法》', 'C. 《中国人民银行法》', 'D. 《公司法》'), JSON_ARRAY('A', 'B', 'C'), '前三部法律构成银行业监管的法律基础。《公司法》适用于所有公司，不专门针对银行业。', 3, 'easy', 3.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('multiple_choice', '银行流动性应急预案应包括？', JSON_ARRAY('A. 触发条件', 'B. 应急资金来源', 'C. 报告路径', 'D. 演练计划'), JSON_ARRAY('A', 'B', 'C', 'D'), '完整的应急预案需涵盖触发、资源、组织、演练四个方面，确保可操作性。', 3, 'medium', 3.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('multiple_choice', '商业银行信息披露应包括？', JSON_ARRAY('A. 财务会计报告', 'B. 风险状况', 'C. 公司治理信息', 'D. 年度重大事项'), JSON_ARRAY('A', 'B', 'C', 'D'), '四个方面的信息披露都能帮助利益相关者全面了解银行的经营和风险状况。', 3, 'easy', 3.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('multiple_choice', '关于贷款拨备，正确的说法有？', JSON_ARRAY('A. 拨备覆盖率不应低于150%', 'B. 贷款拨备率不应低于2.5%', 'C. 拨备计提越多越好', 'D. 拨备是银行抵御信用风险的重要缓冲'), JSON_ARRAY('A', 'B', 'D'), '监管要求拨备覆盖率和拨贷比取孰高值。拨备不是越多越好，过高会影响利润和资本使用效率，需要合理平衡。', 3, 'hard', 3.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('multiple_choice', '银行科技风险管理制度包括？', JSON_ARRAY('A. 系统开发和测试管理', 'B. 信息系统运行维护', 'C. 业务连续性管理', 'D. 外包风险管理'), JSON_ARRAY('A', 'B', 'C', 'D'), '四项都是科技风险管理的重要方面，涵盖系统全生命周期管理。', 3, 'medium', 3.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW());
INSERT INTO busi_questions (question_type, content, options, correct_answer, analysis, category_id, difficulty, default_score, org_id, org_nm, is_deleted, created_by_id, created_at, updated_at) VALUES
('true_false', '巴塞尔协议Ⅲ要求资本充足率不低于8%。', JSON_ARRAY(), '对', '资本充足率最低要求为8%，加上资本留存缓冲(2.5%)后实际要求达到10.5%。', 3, 'easy', 2.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('true_false', '银行可以向关系人发放信用贷款。', JSON_ARRAY(), '错', '根据《商业银行法》，商业银行不得向关系人（董事、监事、管理人员、信贷人员及其近亲属等）发放信用贷款。', 3, 'easy', 2.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('true_false', '操作风险是指由不完善或有问题的内部程序、人员及系统或外部事件所造成损失的风险。', JSON_ARRAY(), '对', '这是巴塞尔委员会对操作风险的标准定义，包含法律风险但不包含策略风险和声誉风险。', 3, 'easy', 2.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('true_false', '银行可以将存款用于股权投资。', JSON_ARRAY(), '错', '我国实行分业经营制度，商业银行在境内不得从事信托投资和证券经营业务，不得向非自用不动产投资或向非银行金融机构和企业投资。', 3, 'medium', 2.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('true_false', '内部控制只是合规部门的事情，与其他部门关系不大。', JSON_ARRAY(), '错', '内部控制是全员参与的管理活动，每位员工都有责任执行内部控制制度。合规部门负责统筹，而非包办。', 3, 'easy', 2.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('true_false', '银行大额风险暴露中，对单一客户的非同业风险暴露不得超过一级资本净额的15%。', JSON_ARRAY(), '对', '这是《商业银行大额风险暴露管理办法》的核心规定，旨在防止风险过度集中。', 3, 'medium', 2.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('true_false', '银行工作人员可以向他人泄露客户存款信息。', JSON_ARRAY(), '错', '根据《商业银行法》，银行有义务为存款人保密，除法律另有规定外，不得向任何单位和个人提供客户信息。', 3, 'easy', 2.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('true_false', '银行拨备覆盖率监管要求不低于150%。', JSON_ARRAY(), '对', '拨备覆盖率=贷款损失准备/不良贷款余额，监管要求不低于150%，即每1元不良贷款至少准备1.5元的损失准备。', 3, 'easy', 2.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('true_false', '银行可以不经过审批程序自行开立分支机构。', JSON_ARRAY(), '错', '根据《商业银行法》，设立分支机构必须经国务院银行业监督管理机构审查批准，取得金融许可证后方可经营。', 3, 'easy', 2.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('true_false', '贷款五级分类中，关注类贷款属于不良贷款。', JSON_ARRAY(), '错', '关注类贷款存在一些不利因素但不构成不良，不良贷款仅包括次级、可疑和损失三类。', 3, 'easy', 2.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('true_false', '银行理财产品的销售需要执行"双录"制度。', JSON_ARRAY(), '对', '根据监管要求，银行销售理财产品时需对销售过程进行录音录像（双录），以规范销售行为和保护投资者。', 3, 'medium', 2.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('true_false', '信贷业务可以不需要贷前调查直接发放。', JSON_ARRAY(), '错', '贷前调查是信贷三查的第一步，是风险识别和客户准入的基础环节，任何贷款发放前都必须完成。', 3, 'easy', 2.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('true_false', '银行的核心一级资本包括实收资本、资本公积、盈余公积和未分配利润。', JSON_ARRAY(), '对', '这四项构成了核心一级资本的主体，是银行吸收损失能力最强的资本层级。', 3, 'easy', 2.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('true_false', '银行可以通过同业业务隐匿不良贷款。', JSON_ARRAY(), '错', '通过同业业务或通道隐匿不良贷款属于违规行为，监管对此有明确的处罚规定。不良贷款应真实反映、足额计提拨备。', 3, 'medium', 2.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('true_false', '银行内部审计部门属于第二道防线。', JSON_ARRAY(), '错', '内部审计属于第三道防线。第一道是业务部门，第二道是风险管理和合规部门，第三道才是内部审计。', 3, 'easy', 2.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('true_false', '商业银行可以投资非自用不动产。', JSON_ARRAY(), '错', '根据《商业银行法》，商业银行在境内不得向非自用不动产投资。投资性房地产也只能是抵债等方式被动取得且在规定期限内处置。', 3, 'medium', 2.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('true_false', '银行反洗钱系统的大额交易报告时间为交易发生后5个工作日内。', JSON_ARRAY(), '对', '根据规定，金融机构应在交易发生后5个工作日内向反洗钱监测分析中心报送大额交易报告。', 3, 'medium', 2.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('true_false', '压力测试只需要由风险管理部门单独完成。', JSON_ARRAY(), '错', '压力测试需要多部门协作：风险管理部门负责模型和情景，业务部门提供数据，财务部门提供财务影响分析，高管层审批。', 3, 'easy', 2.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('true_false', '银行的营业时间可以随意调整变动。', JSON_ARRAY(), '错', '银行的营业时间调整需要向监管部门报备并提前公告，不得擅自停止营业或缩短营业时间。', 3, 'easy', 2.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('true_false', '商业银行的任何董事都可以审批关联交易。', JSON_ARRAY(), '错', '根据《商业银行关联交易管理办法》，关联董事（与关联交易有利害关系的董事）应当回避，不得参与该关联交易的审批。', 3, 'medium', 2.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW());
INSERT INTO busi_questions (question_type, content, options, correct_answer, analysis, category_id, difficulty, default_score, org_id, org_nm, is_deleted, created_by_id, created_at, updated_at) VALUES
('fill_blank', '巴塞尔协议将银行风险分为信用风险、市场风险和______三大类。', JSON_ARRAY(), '操作风险', '信用、市场、操作是巴塞尔协议第一支柱中明确要求计提资本的三大风险类型。', 3, 'easy', 3.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('fill_blank', '信贷业务三查制度是指贷前调查、贷中审查和______。', JSON_ARRAY(), '贷后检查', '三查制度贯穿信贷全流程，是信贷管理的基本制度安排，缺一不可。', 3, 'easy', 3.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('fill_blank', '商业银行资本充足率的最低要求是______%。', JSON_ARRAY(), '8', '资本充足率=(总资本-扣除项)/风险加权资产×100%，监管底线为8%。', 3, 'easy', 3.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('fill_blank', '银行反洗钱制度的核心是______身份识别制度。', JSON_ARRAY(), '客户', '客户身份识别（KYC）是反洗钱的第一道关口，了解你的客户是履行反洗钱义务的基础。', 3, 'easy', 3.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('fill_blank', '商业银行操作风险三大管理工具是RCSA、KRI和______。', JSON_ARRAY(), '损失数据收集(LDC)', 'RCSA(风险与控制自评估)、KRI(关键风险指标)、LDC(损失数据收集)构成操作风险管理的完整工具箱。', 3, 'medium', 3.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('fill_blank', '流动性覆盖率(LCR)的监管最低要求是______%。', JSON_ARRAY(), '100', 'LCR=优质流动性资产/未来30天净现金流出，要求银行在压力情景下能维持至少30天的生存能力。', 3, 'medium', 3.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('fill_blank', '银行贷款五级分类中，次级、可疑和______统称为不良贷款。', JSON_ARRAY(), '损失', '贷款五级分类：正常→关注→次级→可疑→损失，后三类为不良贷款。', 3, 'easy', 3.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('fill_blank', '拨备覆盖率等于贷款损失准备除以______。', JSON_ARRAY(), '不良贷款余额', '拨备覆盖率衡量银行抵御信用风险损失的准备充足程度。', 3, 'easy', 3.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('fill_blank', '银行业的主要监管机构是______。', JSON_ARRAY(), '国家金融监督管理总局', '原银保监会已更名为国家金融监督管理总局，是国务院直属的银行业主要监管机构。', 3, 'easy', 3.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('fill_blank', '银行三道防线中，______属于第一道防线。', JSON_ARRAY(), '业务部门', '第一道防线是业务部门和经营机构，他们是风险的第一识别者和承担者。', 3, 'easy', 3.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('fill_blank', '银行对大额交易的报告时限是交易发生后______个工作日内。', JSON_ARRAY(), '5', '大额交易应在5个工作日内向反洗钱监测分析中心报告。可疑交易发现后即时报告。', 3, 'medium', 3.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('fill_blank', '商业银行不得向______发放信用贷款。', JSON_ARRAY(), '关系人', '关系人包括银行董事、监事、管理人员、信贷人员及其近亲属等。关系人贷款必须提供担保且条件不优于其他借款人。', 3, 'easy', 3.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('fill_blank', '银行理财产品销售需要执行______制度。', JSON_ARRAY(), '双录(录音录像)', '双录是规范理财销售行为、保护消费者权益的重要制度安排，实现销售过程的可追溯。', 3, 'easy', 3.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('fill_blank', 'CAMELS评级体系中的C代表______。', JSON_ARRAY(), '资本充足', 'CAMELS六个字母：C-资本充足、A-资产质量、M-管理、E-盈利、L-流动性、S-市场风险敏感度。', 3, 'hard', 4.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('fill_blank', '银行杠杆率的分子是______资本。', JSON_ARRAY(), '一级', '杠杆率=一级资本净额/(表内资产+表外资产转换后的信用风险暴露)×100%。分子是一级资本而非总资本。', 3, 'hard', 4.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('fill_blank', '商业银行对外股权投资应当经______批准。', JSON_ARRAY(), '国务院银行业监督管理机构', '银行对外股权投资须经监管机构审批，禁止未经批准的股权投资行为。', 3, 'medium', 3.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('fill_blank', '银行年度报告应当在每个会计年度结束后______个月内披露。', JSON_ARRAY(), '4', '根据信息披露规定，银行应在每个会计年度终了后4个月内披露年度报告。', 3, 'easy', 3.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('fill_blank', '银行核心负债依存度等于核心负债除以______。', JSON_ARRAY(), '总负债', '核心负债依存度衡量负债的稳定性，核心负债包括距到期日三个月以上的定期存款和发行债券等稳定资金来源。', 3, 'medium', 3.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('fill_blank', '商业银行的操作风险损失事件应在发现后______个工作日内录入系统。', JSON_ARRAY(), '5', '操作风险损失事件应及时记录和报告，确保损失数据的完整性和及时性，为风险管理提供依据。', 3, 'hard', 4.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('fill_blank', '银行对一般风险的准备金计提比例不低于风险资产期末余额的______%。', JSON_ARRAY(), '1.5', '一般风险准备是银行从税后利润中提取的风险准备金，按风险资产余额的一定比例计提，增强抗风险能力。', 3, 'hard', 4.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW());
INSERT INTO busi_questions (question_type, content, options, correct_answer, analysis, category_id, difficulty, default_score, org_id, org_nm, is_deleted, created_by_id, created_at, updated_at) VALUES
('short_answer', '请简述巴塞尔协议Ⅲ的核心内容。', JSON_ARRAY(), '(1)强化资本监管——提高资本质量和数量要求，引入资本留存缓冲(2.5%)和逆周期缓冲(0-2.5%)；(2)引入杠杆率(≥4%)作为补充指标；(3)建立流动性监管框架——LCR(≥100%)和NSFR(≥100%)；(4)强化系统重要性银行监管——附加资本要求(1-3.5%)。', '巴Ⅲ的核心是构建多层次的监管框架。', 3, 'medium', 5.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('short_answer', '请说明商业银行内部控制的主要措施。', JSON_ARRAY(), '(1)不相容职务分离——授权、执行、记录、保管、审核不能由一人承担；(2)授权审批控制——明确各级审批权限和程序；(3)会计系统控制——真实完整反映业务；(4)财产保护控制——定期盘点对账；(5)预算控制——以预算约束各部门行为；(6)运营分析控制——定期分析经营和风险状况；(7)绩效考评控制——将内控纳入考核体系。', '七项控制措施构成了内控的完整体系。', 3, 'easy', 5.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('short_answer', '请分析银行操作风险的主要类型和典型案例。', JSON_ARRAY(), '七大类型：(1)内部欺诈——员工挪用资金；(2)外部欺诈——伪造票据、网络攻击；(3)雇佣制度和工作场所安全——劳资纠纷；(4)客户、产品和业务活动——不当销售、违反反洗钱；(5)实物资产损坏——自然灾害；(6)系统故障——IT系统崩溃、数据丢失；(7)执行交割和流程管理——交易录入错误、文件遗失。', '操作风险损失事件数据库是定量管理的基础。', 3, 'medium', 5.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('short_answer', '请简述银行反洗钱制度的主要义务。', JSON_ARRAY(), '(1)客户身份识别(KYC)——开立账户时严格审核客户身份，识别受益所有人；(2)大额交易报告——现金交易20万元以上、转账交易200万元以上应报告；(3)可疑交易报告——发现可疑交易即时报告，不受金额限制；(4)客户资料和交易记录保存——至少保存5年；(5)反洗钱培训和宣传——提升全员反洗钱意识和能力；(6)反洗钱内部制度建设——建立专门的反洗钱组织架构和制度体系。', '反洗钱是银行法定义务，违规将面临严厉处罚。', 3, 'easy', 5.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('short_answer', '请解释银行的全面风险管理体系。', JSON_ARRAY(), '全面风险管理(ERM)指银行对信用风险、市场风险、操作风险、流动性风险、声誉风险、战略风险等进行统一识别、评估、监测和控制的体系。核心要素：(1)风险治理架构——董事会最终责任、高管层执行、三道防线运作；(2)风险管理策略——风险偏好、风险限额、风险政策；(3)风险管理流程——识别→评估→控制→监测→报告；(4)风险数据与IT系统——统一的数据标准和系统平台；(5)内部控制和审计——独立评价风险管理的有效性。', '全面风险管理是现代银行的生命线。', 3, 'medium', 5.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('short_answer', '请说明商业银行公司治理结构的核心要求。', JSON_ARRAY(), '核心要求：(1)健全的组织架构——股东大会、董事会、监事会、高管层各司其职；(2)清晰的职责边界——决策权、执行权、监督权相互分离；(3)有效的制衡机制——独立董事制度、关联交易回避制度；(4)科学的决策规则——重大事项需董事会表决通过；(5)透明的信息披露——及时准确披露经营和风险信息；(6)完善的激励约束——薪酬与风险挂钩，实行延期支付和追索扣回。', '良好的公司治理是银行长期稳健经营的基石。', 3, 'easy', 5.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('short_answer', '请分析银行流动性风险的管理策略。', JSON_ARRAY(), '管理策略：(1)资产负债期限匹配——避免短借长贷，控制期限错配缺口；(2)核心存款管理——提升稳定低成本的存款比例；(3)备付金管理——保持合理超额准备金应对日常波动；(4)限额管理——设置LCR、NSFR、流动性缺口率等指标的限额；(5)应急计划——建立流动性应急预案和紧急融资渠道；(6)压力测试——定期进行流动性压力测试检验应对极端情况的能力。', '流动性是银行的命脉，流动性危机是银行最常见的倒闭原因。', 3, 'medium', 5.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('short_answer', '请简述银行信贷管理的全流程操作要点。', JSON_ARRAY(), '贷前：(1)客户受理与准入；(2)尽职调查——了解客户经营、财务、信用状况；(3)信用评级——评定客户信用等级；(4)担保评估——核实担保价值。贷中：(5)独立审批——审贷分离，分级授权审批；(6)合同签订——规范合同管理；(7)放款审核——审核放款条件满足后发放。贷后：(8)定期检查——跟踪贷款使用和客户情况；(9)风险预警——发现风险信号及时预警；(10)分类管理——按五级分类持续评估；(11)不良处置——清收、重组、核销。', '三查制度的严格执行是信贷质量的生命线。', 3, 'easy', 5.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('short_answer', '请解释商业银行的资本管理策略。', JSON_ARRAY(), '资本规划：根据发展战略和风险偏好制定中长期资本规划。资本筹集：(1)内源融资——利润留存转增资本；(2)外源融资——增发股票、发行资本债券（二级资本债、永续债）。资本配置：将资本向风险调整后收益(RAROC)高的业务倾斜。资本监控：持续监测各项资本充足率指标，确保满足监管要求和内部管理需要。压力测试：模拟不利情景下的资本消耗，评估资本充足性。', '资本是银行吸收非预期损失的最后保障。', 3, 'medium', 5.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('short_answer', '请说明银行关联交易管理的主要规定。', JSON_ARRAY(), '关联方范围：(1)自然人——董监高及其近亲属、持股5%以上主要股东；(2)法人——上述自然人和法人控制的法人。重大关联交易：交易金额占银行资本净额1%以上，需董事会审批。一般关联交易：按规定程序审批。禁止行为：不得向关联方发放无担保贷款，不得以优于非关联方的条件与关联方交易，关联董事需回避表决。信息披露：在年报中披露关联交易情况。', '关联交易管理不当是银行公司治理的常见缺陷。', 3, 'medium', 5.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('short_answer', '请分析商业银行的压力测试框架。', JSON_ARRAY(), '测试类型：(1)敏感性分析——单因素变动的影响；(2)情景分析——多种因素同时变化的影响；(3)反向压力测试——寻找导致银行无法生存的情景。常见情景：GDP大幅下滑、房价暴跌、利率急升、汇率巨幅波动、市场流动性枯竭。工作流程：情景设计→影响传导→结果汇总→应对措施→报告。频率：至少每年一次全面压力测试，市场风险和流动性风险应更高频率。结果运用：指导风险限额设定、资本规划、应急预案制定。', '压力测试是银行风险管理的"体检"。', 3, 'hard', 6.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('short_answer', '请说明银行消费者权益保护的主要制度。', JSON_ARRAY(), '(1)信息披露制度——用通俗易懂的语言向消费者充分披露产品信息；(2)适当性管理制度——将合适的产品销售给合适的客户，进行风险承受能力评估；(3)销售行为规范——理财销售执行"双录"，不得误导、欺诈；(4)投诉处理机制——设立专门的投诉渠道，按时处理回复；(5)个人信息保护——依法收集、使用和保护消费者个人信息；(6)金融知识普及——开展消费者教育活动。', '消费者权益保护是银行业的法定义务和社会责任。', 3, 'easy', 5.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('short_answer', '请简述银行经济资本管理的概念和意义。', JSON_ARRAY(), '经济资本是银行在一定的置信区间下，为覆盖非预期损失所需要持有的资本量。与监管资本的区别：经济资本基于银行自身的风险模型计算，反映实际风险水平；监管资本按监管规则计算。作用：(1)风险衡量——量化各类风险的资本需求；(2)绩效考核——计算风险调整后收益率(RAROC=净利润/经济资本)；(3)资本配置——将稀缺资本配置到高RAROC业务；(4)产品定价——在定价中考虑资本成本。', '经济资本管理是银行精细化管理的高级阶段。', 3, 'hard', 6.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('short_answer', '请分析银行信息科技风险管理的关键领域。', JSON_ARRAY(), '关键领域：(1)信息安全管理——访问控制、数据加密、网络安全；(2)系统开发和测试——需求管理、代码管理、测试环境与生产环境分离；(3)运行维护——容量管理、变更管理、故障处理；(4)业务连续性——容灾备份、灾难恢复演练；(5)外包管理——外包商准入、定期评估、数据保密；(6)数据治理——数据标准、数据质量、数据安全。监管要求：建立首席信息官制度，重大科技事件必须报告。', '银行对IT的依赖性决定了科技风险管理的战略重要性。', 3, 'medium', 5.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('short_answer', '请说明银行合规管理制度的基本框架。', JSON_ARRAY(), '组织架构：(1)董事会——审批合规政策、对合规负最终责任；(2)高管层——执行合规政策、建立合规部门；(3)合规部门——独立于经营部门、直接向高管层和董事会报告；(4)全员合规——每一位员工对自己的行为合规负责。制度建设：(5)合规手册——银行内部的基本行为准则；(6)规章制度——各业务线的具体操作规程；(7)培训制度——定期开展合规培训；(8)合规考核——将合规纳入绩效考核；(9)违规问责——对违规行为实施问责和处罚。', '"合规创造价值"已成为银行业共识。', 3, 'medium', 5.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('short_answer', '请阐述商业银行流动性覆盖率(LCR)的计算和监管要求。', JSON_ARRAY(), '公式：LCR=优质流动性资产/未来30天净现金流出×100%。分子：优质流动性资产(HQLA)包括一级资产（现金、央行准备金、国债等）和二级资产（A级公司债、AA-以上住房抵押贷款证券等折价计入）。分母：压力情景下未来30天的净现金流出，包括零售存款流失、批发性融资流失、衍生品抵押品需求等。监管要求：LCR≥100%，即优质流动性资产足够覆盖30天的净现金流出。', 'LCR是防止银行在短期压力下出现流动性危机的关键指标。', 3, 'hard', 6.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('short_answer', '请分析银行绩效考核中引入风险调整指标的意义和方法。', JSON_ARRAY(), '传统考核缺陷：只考核利润绝对额，不考核获得利润所承担的风险。风险调整方法：(1)RAROC=风险调整后收益/经济资本，衡量单位风险资本的盈利水平；(2)EVA=净利润-经济资本×资本成本率，衡量扣除风险成本后的真实经济价值。实施要点：(1)建立风险量化模型；(2)确定各业务线的经济资本分配；(3)设置以RAROC/EVA为核心的考核指标；(4)薪酬与风险调整后的绩效挂钩，实行延期支付和追索扣回。', '风险调整后的绩效考核能有效避免短期行为和过度风险承担。', 3, 'hard', 6.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW()),
('short_answer', '请简述银行重大风险事件报告制度。', JSON_ARRAY(), '报告范围：涉及金额较大、影响范围较广、性质严重的事件。包括但不限于：(1)信用风险——大额不良贷款、客户违约；(2)市场风险——交易亏损超过限额；(3)操作风险——系统故障、内外欺诈、重大差错；(4)流动性风险——支付困难、挤兑风险；(5)声誉风险——媒体负面报道、集体投诉。报告要求：事发后即时口头报告、24小时内书面报告、持续报告处置进展。报告路径：逐级上报，重大事件直达董事会。', '及时准确的风险报告是管理层快速应对危机的前提。', 3, 'easy', 5.00, 'ORG001', '总行营业部', 0, 1, NOW(), NOW()),
('short_answer', '请说明银行年度报告中关于风险管理应披露的内容。', JSON_ARRAY(), '应披露内容：(1)风险管理架构——治理结构、组织体系、风险政策；(2)信用风险——信用风险敞口、不良贷款、拨备、五级分类；(3)市场风险——利率、汇率、商品风险敞口、VaR值；(4)操作风险——损失事件、管理措施；(5)流动性风险——LCR、NSFR、流动性缺口；(6)资本管理——资本构成、资本充足率、杠杆率；(7)并表管理——集团层面的风险状况。披露原则：全面、准确、及时、可比。', '信息披露是巴塞尔协议第三支柱"市场约束"的核心内容。', 3, 'medium', 5.00, 'ORG003', '支行网点', 0, 1, NOW(), NOW()),
('short_answer', '请分析银行制度执行中常见的合规风险及防范措施。', JSON_ARRAY(), '常见风险：(1)制度形同虚设——有制度不执行，或有制度不可操作；(2)制度滞后——未能跟上监管政策变化；(3)执行的模糊边界——制度规定不明确导致执行偏差；(4)选择性执行——有利则执行、无利则绕过。防范措施：(1)制度制定的可操作性——制度起草广泛征求意见、进行可行性评估；(2)制度的定期重检——至少每年审查一次制度的有效性；(3)制度的培训宣导——确保每位员工理解并掌握相关制度要求；(4)制度执行的监督和检查——通过自查、互查、审计确保制度落实；(5)制度执行的考核问责——将制度执行情况纳入绩效考核和问责体系。', '制度的生命力在于执行，再好再全的制度不执行等于零。', 3, 'easy', 5.00, 'ORG002', '分行营业部', 0, 1, NOW(), NOW());
